import type { Drill } from "./types";

// Sales / early drills, keyed by module slug — 25 per module.
// Pitched at SDRs, junior AEs, and marketing coordinators: cold outreach,
// discovery recaps, objection handling, pipeline updates, campaign recaps,
// event follow-ups, and CS handoffs. Merged into course.ts.
export const SALES_EARLY_DRILLS: Record<string, Drill[]> = {
  "lead-with-the-point": [
    {"id":"lead-sales-early-01","level":"early","profession":"sales","title":"The cold email that buries the hook","scenario":"You're an SDR writing a cold email to an operations manager at a logistics company. Your draft opens with two sentences about your company's founding story before mentioning that you help teams like hers cut invoice processing time in half.","task":"Rewrite the opening 1-2 sentences so the reason she should care comes first.","tips":["Sentence one should be about her problem, not your company.","The founding story earns zero replies — cut it.","If she reads only the first line, she should know why you wrote."],"focus":["clarity","impact"],"placeholder":"Teams like yours at [company] are losing 10+ hours a week to manual invoicing —"},
    {"id":"lead-sales-early-02","level":"early","profession":"sales","title":"The pipeline update that hides the news","scenario":"Your manager asked for a quick Slack update on the Meridian deal. The real news: they signed this morning. Your draft recaps the last three calls before mentioning the signature.","task":"Write a 1-2 sentence update that leads with the close.","tips":["The signature is the headline — say it in the first five words.","The call history is backstory; your manager can ask if they want it.","Good news buried reads like bad news coming."],"focus":["structure","concision"],"placeholder":"Meridian signed this morning —"},
    {"id":"lead-sales-early-03","level":"early","profession":"sales","title":"The discovery recap with no next step","scenario":"You just finished a strong discovery call with a prospect who agreed to bring her VP to a demo next Thursday. Your recap email draft summarizes everything discussed before mentioning the demo in the last line.","task":"Write a recap email opening that leads with the agreed next step.","tips":["The confirmed demo is the most actionable line — put it first.","Recap details support the next step, not the other way around.","Make the date and attendees unmissable."],"focus":["structure","clarity"],"placeholder":"Confirming our demo Thursday at 2pm with you and your VP —"},
    {"id":"lead-sales-early-04","level":"early","profession":"sales","title":"The follow-up that circles","scenario":"A prospect went quiet after your first call two weeks ago. Your follow-up draft opens with 'Just circling back' and three sentences of pleasantries before asking for 15 minutes next week.","task":"Rewrite the follow-up so the specific ask comes in sentence one.","tips":["Lead with the ask: 15 minutes, next week, and why it's worth it.","'Circling back' tells them nothing new — give a reason to reply.","One clear ask beats three soft ones."],"focus":["clarity","concision"]},
    {"id":"lead-sales-early-05","level":"early","profession":"sales","title":"The discount approval request","scenario":"You need your manager to approve a 15% discount to close the Brightline deal by Friday. Your draft message walks through the whole negotiation history before getting to the approval you need.","task":"Write a message that puts the approval request and deadline in the first sentence.","tips":["Lead with what you need, the number, and by when.","The negotiation story is support — two lines max, below the ask.","Make it answerable with a yes or no."],"focus":["clarity","impact"],"placeholder":"Requesting approval for 15% off Brightline to close by Friday —"},
    {"id":"lead-sales-early-06","level":"early","profession":"sales","title":"The meeting-booked handoff","scenario":"You're an SDR who just booked a meeting with a director at a 500-person target account. Your Slack message to the AE describes the whole call before mentioning the booked meeting and its date.","task":"Write a 2-3 sentence handoff that leads with the booked meeting.","tips":["First line: who, when, and what they want to discuss.","Call color is useful but secondary — keep it brief.","The AE triages by the first line; make it count."],"focus":["structure","clarity"]},
    {"id":"lead-sales-early-07","level":"early","profession":"sales","title":"The objection reply that stalls","scenario":"A prospect emailed: 'We're worried your tool won't integrate with our CRM.' It does — natively. Your reply draft spends a paragraph on your integration philosophy before saying so.","task":"Write a reply where the direct answer comes first.","tips":["Answer in sentence one: yes, it integrates natively.","Then offer proof — a doc, a customer, a quick screen share.","Every sentence before the answer erodes confidence."],"focus":["clarity","impact"],"placeholder":"Yes — we integrate natively with your CRM."},
    {"id":"lead-sales-early-08","level":"early","profession":"sales","title":"The campaign recap that meanders","scenario":"You're a marketing coordinator reporting on last month's email campaign. The headline: it generated 42 qualified leads, double the target. Your draft opens with methodology and send-time analysis.","task":"Write the first two sentences of the recap, leading with the headline result.","tips":["Lead with the number that matters and how it compares to target.","Methodology belongs in an appendix or below the fold.","Your manager forwards the first line — write it forwardable."],"focus":["structure","impact"],"placeholder":"The March campaign generated 42 qualified leads — double our target of 21."},
    {"id":"lead-sales-early-09","level":"early","profession":"sales","title":"The event follow-up with a buried ask","scenario":"You met a promising prospect at a trade show booth yesterday. Your follow-up email reminisces about the conversation for a paragraph before proposing a call.","task":"Write a follow-up that proposes the call in the first two sentences.","tips":["Reference the conversation in half a sentence, then get to the ask.","Propose specific times — vague 'sometime' asks die.","Warmth and directness are not opposites."],"focus":["clarity","concision"]},
    {"id":"lead-sales-early-10","level":"early","profession":"sales","title":"The demo help request","scenario":"You need a sales engineer to join Thursday's demo because the prospect has deep API questions. Your draft explains the whole deal background before asking for their time.","task":"Write a Slack message that leads with the ask: Thursday, 45 minutes, API questions.","tips":["Lead with the request and the time commitment.","One line of deal context is enough for them to say yes.","Make the specific expertise you need explicit."],"focus":["clarity","concision"],"placeholder":"Can you join my demo Thursday 2-2:45pm? The prospect has deep API questions —"},
    {"id":"lead-sales-early-11","level":"early","profession":"sales","title":"The lost deal you don't want to report","scenario":"The Hartwell deal — your biggest this quarter — just told you they chose a competitor. Your message to your manager opens with everything you tried before admitting the loss.","task":"Write a 2-3 sentence message that states the loss up front.","tips":["Lead with the outcome: lost, to whom, and the stated reason.","What you tried comes after, briefly.","Reporting losses cleanly builds more trust than softening them."],"focus":["clarity","impact"],"placeholder":"We lost Hartwell to Competitor X — they cited price."},
    {"id":"lead-sales-early-12","level":"early","profession":"sales","title":"The renewal risk flag","scenario":"On a check-in call, a customer mentioned their team barely uses the product and budget review is next month. You need to flag this to the CS team, but your draft opens with a friendly recap of the whole call.","task":"Write a message to CS that leads with the churn risk.","tips":["First line: this account is at risk, and why.","The call recap supports the flag — put it after.","Urgency should be readable from the opening words."],"focus":["impact","clarity"],"placeholder":"Flagging churn risk on Acme: low usage and a budget review next month."},
    {"id":"lead-sales-early-13","level":"early","profession":"sales","title":"The pricing question dodge","scenario":"A prospect emailed asking directly what the 20-seat plan costs. You know the number: $12,000 a year. Your draft reply talks about value and flexible packaging before revealing anything.","task":"Write a reply that gives the number first, then one sentence of context.","tips":["Answer the question asked: the price, in sentence one.","Context on what's included comes after the number.","Dodging a direct question costs more trust than any price."],"focus":["clarity","precision"],"placeholder":"The 20-seat plan is $12,000 a year."},
    {"id":"lead-sales-early-14","level":"early","profession":"sales","title":"The Friday forecast email","scenario":"Your manager needs your weekly forecast. The headline: you're committing $38K this month, up from $30K last week because Meridian verbally confirmed. Your draft opens with a recap of every deal in your pipeline.","task":"Write the opening 1-2 sentences that lead with the commit number and what changed.","tips":["The commit number is the answer to the email — lead with it.","Name the one change that moved the number.","Deal-by-deal detail goes below, skimmable."],"focus":["precision","structure"],"placeholder":"Committing $38K this month, up from $30K —"},
    {"id":"lead-sales-early-15","level":"early","profession":"sales","title":"The referral ask hiding in gratitude","scenario":"A happy customer just told you the product saved her team a full day a week. You want to ask her for an intro to her counterpart at a sister company, but your draft is three paragraphs of thanks with the ask in the last line.","task":"Write a message that makes the intro request clear within the first two sentences.","tips":["Pair the thanks and the ask early — don't make her hunt for it.","Name exactly who you'd like to meet and why.","Offer to draft the intro note so saying yes is effortless."],"focus":["clarity","audience"]},
    {"id":"lead-sales-early-16","level":"early","profession":"sales","title":"The competitor undercut escalation","scenario":"Your prospect just told you a competitor offered the same scope at 30% less, and they decide Monday. You need your manager's input today. Your draft message tells the deal's whole story first.","task":"Write a message that leads with the situation and the decision you need by when.","tips":["First sentence: competitor at -30%, decision Monday, need your call today.","Keep the history to one supporting line.","A clear deadline gets a fast response."],"focus":["clarity","impact"],"placeholder":"Need your call today: competitor undercut us 30% on Delta Corp and they decide Monday."},
    {"id":"lead-sales-early-17","level":"early","profession":"sales","title":"The voicemail that gets deleted","scenario":"You're leaving a voicemail for a prospect who downloaded your pricing guide yesterday. Your usual voicemail spends 20 seconds on your name, company, and how you found them before saying anything useful.","task":"Write a 3-4 sentence voicemail script that leads with why you're calling.","tips":["Open with the reason that's relevant to them, not your intro.","Name and callback number go at the end, said slowly.","One idea per voicemail — the callback is the goal."],"focus":["concision","impact"]},
    {"id":"lead-sales-early-18","level":"early","profession":"sales","title":"The budget request that wanders","scenario":"You want $3,000 to sponsor a booth at a regional industry meetup where 40 target accounts will attend. Your draft email to your manager describes the event's history before naming the amount or the ask.","task":"Write an email opening that leads with the ask, the amount, and the payoff.","tips":["Sentence one: the amount, the event, and what it buys us.","The 40 target accounts is your strongest line — use it early.","Approval requests should be scannable in five seconds."],"focus":["clarity","impact"],"placeholder":"Requesting $3,000 to sponsor the Midwest Ops Meetup — 40 of our target accounts attend."},
    {"id":"lead-sales-early-19","level":"early","profession":"sales","title":"The yes/no security question","scenario":"A prospect's IT lead emailed one question: 'Is customer data encrypted at rest?' It is. Your draft reply opens with two paragraphs about your security culture before answering.","task":"Write a reply that answers yes in the first word or two, then adds one line of substance.","tips":["Answer first: yes.","One concrete supporting fact beats two paragraphs of posture.","Offer the security doc as the follow-up, not the answer."],"focus":["clarity","concision"],"placeholder":"Yes — all customer data is encrypted at rest (AES-256)."},
    {"id":"lead-sales-early-20","level":"early","profession":"sales","title":"The handoff note that buries the landmine","scenario":"You're handing a new customer to customer success. Everything is smooth except one thing: the buyer expects a custom report feature that doesn't ship until Q3. Your handoff note lists account basics for two paragraphs before mentioning it.","task":"Rewrite the note's opening so the one thing CS must know comes first.","tips":["Lead with the expectation gap — it's the only thing that can blow up.","Standard account details can follow in a tidy block.","If CS reads one line, it should be the landmine."],"focus":["structure","impact"],"placeholder":"One thing to manage carefully: the buyer expects custom reports, which don't ship until Q3."},
    {"id":"lead-sales-early-21","level":"early","profession":"sales","title":"The slipped close date","scenario":"The Fairview deal you forecast for this month just told you legal review pushes signature to next month. Your message to your manager opens with reassurances about how strong the deal still is.","task":"Write a 2-3 sentence message that states the new close date up front.","tips":["Lead with the slip and the new date.","Then one line on why, one line on why it's still solid.","Managers forgive slips; they don't forgive surprises."],"focus":["clarity","precision"],"placeholder":"Fairview slips to next month — legal review adds 3 weeks."},
    {"id":"lead-sales-early-22","level":"early","profession":"sales","title":"The case study request","scenario":"You need marketing to send you the manufacturing case study by Wednesday for a proposal. Your draft to the marketing coordinator explains the whole deal before making the request.","task":"Write a 1-2 sentence request that leads with what you need and by when.","tips":["Lead with the artifact and the deadline.","One clause of context is plenty — 'for a proposal due Thursday.'","Specific requests get faster answers than story-first ones."],"focus":["concision","clarity"]},
    {"id":"lead-sales-early-23","level":"early","profession":"sales","title":"The post-demo recap that forgets the decision","scenario":"After yesterday's demo, the prospect needs to decide by Friday whether to start a pilot. Your recap email draft lists every feature shown before mentioning the decision and its deadline.","task":"Write a recap opening that leads with the decision on the table and the date.","tips":["First line: the decision, the deadline, and what you need from them.","Feature recap supports the decision — trim it to what they reacted to.","End with one clear question, not three."],"focus":["structure","clarity"]},
    {"id":"lead-sales-early-24","level":"early","profession":"sales","title":"The LinkedIn message nobody finishes","scenario":"You're messaging a marketing director on LinkedIn. Only the first line shows in her notification preview. Your draft starts with 'Hi! Hope you're having a great week. I wanted to reach out because...'","task":"Write a LinkedIn message whose first line earns the click.","tips":["The preview line is the whole battle — put the relevance there.","Cut every word before the point.","Reference something specific to her, not your pitch."],"focus":["impact","concision"],"placeholder":"Your post on lead-routing delays — we cut that to under 5 minutes for teams like yours."},
    {"id":"lead-sales-early-25","level":"early","profession":"sales","title":"The team meeting deal update","scenario":"It's your turn in Monday pipeline review to update the team on your top deal. You tend to narrate every email exchange since last week before saying where the deal actually stands.","task":"Write a 1-2 sentence spoken update that leads with the deal's status.","tips":["First words: stage, dollar amount, close date.","One sentence on what changed since last week.","Say what you need from the room, or say nothing more."],"focus":["concision","structure"],"placeholder":"Northgate is at contract stage, $24K, closing the 28th —"}
  ],
  "start-with-the-audience": [
    {"id":"audience-sales-early-01","level":"early","profession":"sales","title":"The jargon-heavy cold email","scenario":"Your cold email draft to a warehouse operations manager reads: 'Our AI-powered platform leverages workflow orchestration to optimize fulfillment KPIs.' She thinks in shipments, errors, and overtime hours — not in platform-speak.","task":"Rewrite the pitch sentence in her language, tied to her day.","tips":["Swap every abstraction for something she can picture: shipments, mispicks, overtime.","One concrete outcome beats three buzzwords.","Read it aloud as her — would it mean anything?"],"focus":["audience","clarity"],"placeholder":"When orders spike, your team shouldn't have to work Saturdays to keep up —"},
    {"id":"audience-sales-early-02","level":"early","profession":"sales","title":"Pitching the CFO, not the user","scenario":"Your deal's economic buyer is a CFO joining Thursday's call. Your usual pitch is about time savings and happier teams. The CFO cares about cost, risk, and payback period.","task":"Write 2-3 sentences of your pitch reframed for a CFO.","tips":["Translate hours saved into dollars and payback months.","Name the risk of the status quo in financial terms.","Drop the features; keep the economics."],"focus":["audience","precision"],"placeholder":"At your team's volume, this pays for itself in under 5 months —"},
    {"id":"audience-sales-early-03","level":"early","profession":"sales","title":"One recap, two readers","scenario":"After a group call, you're writing one recap email that will reach both the hands-on evaluator and her busy director. You can't serve both equally — the director decides, the evaluator advises.","task":"Write the recap's opening 2-3 sentences aimed at the director as the primary reader.","tips":["Pick one primary audience and write to them; the other reads over their shoulder.","Lead with the decision-relevant summary, not the technical detail.","Put evaluator-level detail in a labeled section below."],"focus":["audience","structure"]},
    {"id":"audience-sales-early-04","level":"early","profession":"sales","title":"Campaign metrics for the sales floor","scenario":"You're a marketing coordinator announcing to the sales team that the webinar drew 300 registrants with a 40% attendance rate and strong engagement scores. The reps only care about one thing: who should they call, and when.","task":"Rewrite the announcement in 2-3 sentences framed around what reps should do.","tips":["Translate registrants into 'leads in your queue' with a count.","Tell them exactly where the list is and how it's prioritized.","Engagement scores matter only if you say what they mean for calling order."],"focus":["audience","impact"],"placeholder":"You have 120 webinar attendees in your queue, hottest first —"},
    {"id":"audience-sales-early-05","level":"early","profession":"sales","title":"The handoff written for you, not CS","scenario":"Your CS handoff note reads like your deal diary: how you found the lead, the demos you ran, the discount battle. CS needs different things — the customer's goal, promises made, key contacts, and go-live expectations.","task":"Rewrite the note's first 3-4 sentences around what CS needs to act on.","tips":["Ask what the reader will do with the note, then lead with that.","Your sales journey is trivia to CS; the customer's success criteria are gold.","List promises made — that's what burns CS later."],"focus":["audience","structure"]},
    {"id":"audience-sales-early-06","level":"early","profession":"sales","title":"Explaining a price increase to a customer","scenario":"Your company is raising prices 8% at renewal. The internal memo talks about 'aligning pricing with expanded platform value.' Your customer, an office manager watching her budget, will read that as spin.","task":"Write 2-3 sentences explaining the increase in terms she'll respect.","tips":["Say the number plainly and when it takes effect.","Name what she's gained this year in her terms, not 'platform value.'","Tell her the one thing she can do about it (lock in early, adjust seats)."],"focus":["audience","clarity"]},
    {"id":"audience-sales-early-07","level":"early","profession":"sales","title":"The VP-level pipeline answer","scenario":"Your VP of Sales stops by and asks how your pipeline looks. You start describing individual prospects' personalities and email threads. The VP thinks in coverage, commit, and risk.","task":"Write the 2-sentence answer calibrated to a VP's altitude.","tips":["Give the shape: pipeline coverage, what's committed, what's at risk.","Names of deals only if they're big enough for a VP to know.","Save the anecdotes for your manager's 1:1."],"focus":["audience","concision"],"placeholder":"I'm at 3x coverage with $38K committed —"},
    {"id":"audience-sales-early-08","level":"early","profession":"sales","title":"Why this lead is worth the AE's time","scenario":"You're an SDR passing a lead to a skeptical senior AE. Your notes describe the nice conversation you had. The AE qualifies on budget, authority, need, and timeline — and deletes vague handoffs.","task":"Write a 3-sentence handoff that speaks to the AE's qualification criteria.","tips":["Map your call notes to what the AE screens for: budget, authority, need, timing.","'Great conversation' is your experience, not their evidence.","Flag the one gap honestly — it builds credibility."],"focus":["audience","precision"]},
    {"id":"audience-sales-early-09","level":"early","profession":"sales","title":"Implementation, minus the jargon","scenario":"A prospect asks what implementation looks like. Your solutions team's answer involves 'sandbox provisioning, SSO configuration, and data migration sprints.' The prospect is an HR manager who has never run a software rollout.","task":"Explain the implementation in 3-4 sentences she can follow and repeat internally.","tips":["Describe it as what her team does and for how long, week by week.","Replace each technical step with its purpose in plain words.","End with the reassurance she's really asking for: effort and risk."],"focus":["audience","clarity"],"placeholder":"Your team's part takes about 3 hours over 2 weeks."},
    {"id":"audience-sales-early-10","level":"early","profession":"sales","title":"Writing to procurement","scenario":"The deal has moved to procurement. Your champion loved talking outcomes, but procurement cares about contract terms, data handling, payment schedules, and vendor risk. Your first email to them still reads like a sales pitch.","task":"Write a 2-3 sentence opening email to procurement in their register.","tips":["Lead with what they need to process the deal: docs, terms, timelines.","Drop the persuasion — the sale is made; you're now reducing friction.","Anticipate their checklist and offer it before they ask."],"focus":["audience","structure"]},
    {"id":"audience-sales-early-11","level":"early","profession":"sales","title":"Attribution without the acronyms","scenario":"Your sales manager asks why marketing credits the webinar for a deal he thinks his rep sourced. Your instinct is to explain multi-touch attribution models. He just wants to know if the numbers are fair.","task":"Explain in 2-3 sentences, without marketing jargon, how the credit works and why.","tips":["Answer his real question first: is the credit fair, and does it cost his rep anything?","Use one plain analogy instead of the model's name.","Offer the detail as an option, not a lecture."],"focus":["audience","clarity"]},
    {"id":"audience-sales-early-12","level":"early","profession":"sales","title":"The demo invite for a busy director","scenario":"You're inviting an operations director to a demo. Your draft lists the six product areas you'll cover. She told you her one pain: order errors doubling as the team scales.","task":"Rewrite the invite in 2-3 sentences built entirely around her stated pain.","tips":["Her words from the call are your best copy — reuse them.","Promise the demo answers her problem, not that it tours your product.","Six topics signal none of them are about her."],"focus":["audience","impact"],"placeholder":"You mentioned order errors have doubled as the team scales — the demo will show exactly how"},
    {"id":"audience-sales-early-13","level":"early","profession":"sales","title":"The limitation, translated","scenario":"Your product syncs data every hour, not in real time. A prospect's office coordinator asks if the dashboard is 'live.' The honest technical answer is 'hourly batch sync.' She needs to know what that means for her workday.","task":"Answer honestly in 2-3 sentences, framed in terms of her actual use.","tips":["Translate 'hourly sync' into what she'd notice: numbers refresh every hour.","Then say whether that matters for how she said she'd use it.","Honest framing beats technically-true evasion."],"focus":["audience","clarity"]},
    {"id":"audience-sales-early-14","level":"early","profession":"sales","title":"Features into outcomes for a clinic","scenario":"You sell scheduling software and you're writing to a dental clinic's office manager. Your product sheet says: 'automated reminders, waitlist backfill, and no-show analytics.' She measures her week in empty chairs and phone time.","task":"Rewrite the three features as 2-3 sentences of outcomes in her world.","tips":["Each feature becomes a moment in her day that gets easier.","'Waitlist backfill' is 'cancelled slots fill themselves.'","Numbers she'd recognize (no-shows per week) land harder than analytics."],"focus":["audience","impact"],"placeholder":"When a patient cancels, the slot fills itself from your waitlist —"},
    {"id":"audience-sales-early-15","level":"early","profession":"sales","title":"Arming your champion","scenario":"Your champion needs to pitch the purchase to her COO next week. She asked for 'something I can send him.' Your instinct is to forward your standard deck. Her COO will give it ninety seconds.","task":"Write the 3-4 sentence summary she can paste into an email to her COO.","tips":["Write in her voice, for his priorities: cost, risk, payoff.","One number, one risk addressed, one clear recommendation.","If your champion has to translate it, you've failed her."],"focus":["audience","concision"]},
    {"id":"audience-sales-early-16","level":"early","profession":"sales","title":"One invite, one audience","scenario":"You're a marketing coordinator drafting the invitation for a product roadshow. Half the invite list is existing customers, half is cold prospects. Your draft tries to speak to both and lands with neither.","task":"Pick one primary audience and write the 2-sentence invitation hook for them.","tips":["Choose the audience the event most needs — then commit fully.","Customers want what's new for them; prospects want why anyone uses you.","Two half-messages are weaker than one whole one."],"focus":["audience","impact"]},
    {"id":"audience-sales-early-17","level":"early","profession":"sales","title":"Same numbers, different reader","scenario":"The monthly newsletter got a 22% open rate and drove 15 demo requests. You report to your marketing manager, who thinks in benchmarks and trends — but today the sales director asked what the newsletter 'actually does.'","task":"Write a 2-sentence answer for the sales director, not your manager.","tips":["The sales director's unit of value is meetings and pipeline, not open rates.","Lead with the 15 demo requests and what they turned into.","Keep the marketing metrics unless he asks."],"focus":["audience","precision"],"placeholder":"Last month's newsletter put 15 demo requests into the pipeline —"},
    {"id":"audience-sales-early-18","level":"early","profession":"sales","title":"The security answer relay","scenario":"Your sales engineer answered the prospect's security question with a paragraph about SOC 2 Type II, TLS 1.3, and RBAC. You need to relay it to the buyer — an operations manager, not a security specialist — without mangling it or drowning her.","task":"Write a 2-3 sentence relay that keeps the substance but fits the reader.","tips":["Lead with the plain-language conclusion: your data is protected and audited.","Keep one or two credibility markers (SOC 2) and cut the rest.","Attach the full answer for her IT team — right altitude for each reader."],"focus":["audience","clarity"]},
    {"id":"audience-sales-early-19","level":"early","profession":"sales","title":"The renewal email about them","scenario":"You're drafting a renewal reminder for a customer 60 days out. Your template talks about 'continuing the partnership.' Their actual story: they processed 4,000 orders through your tool this year and cut errors by a third.","task":"Rewrite the renewal opening in 2-3 sentences built on their results.","tips":["Open with their numbers, not your relationship language.","Their usage data is the strongest renewal argument you have.","Make the renewal feel like protecting a result, not paying a bill."],"focus":["audience","impact"],"placeholder":"Your team ran 4,000 orders through the platform this year, with errors down a third —"},
    {"id":"audience-sales-early-20","level":"early","profession":"sales","title":"The referral framed for the giver","scenario":"You want a happy customer to introduce you to a peer at another company. Your draft explains how much the intro would help you hit quota. The customer doesn't care about your quota — she cares about her peer and her own reputation.","task":"Rewrite the ask in 2-3 sentences framed around what her peer would gain.","tips":["Frame the intro as her doing her peer a favor, not you one.","Make the ask safe for her reputation — offer a no-pressure framing.","Write the forwardable blurb so she doesn't have to."],"focus":["audience","clarity"]},
    {"id":"audience-sales-early-21","level":"early","profession":"sales","title":"'We already use a competitor'","scenario":"A prospect replies: 'We already use CompetitorX.' Your draft reply lists your feature advantages. Her real concern isn't features — it's the pain and risk of switching tools mid-year.","task":"Write a 2-3 sentence reply that speaks to the switching concern, not the feature war.","tips":["Address the fear she didn't state: migration pain, retraining, disruption.","One line on why people switch; one line on how easy you make it.","Feature lists validate her staying put."],"focus":["audience","impact"]},
    {"id":"audience-sales-early-22","level":"early","profession":"sales","title":"The feature request, translated for product","scenario":"Three prospects this month asked for bulk export. You're writing to the product team, who ignore 'sales wants a feature' messages but respond to user problems and deal evidence.","task":"Write a 3-sentence request in the product team's language: problem, evidence, impact.","tips":["Lead with the user problem, not the feature name.","Quantify: three deals this month, roughly what dollar value.","Describe what users are doing today as the workaround — product teams love that."],"focus":["audience","precision"],"placeholder":"Three prospects this month ($40K combined) hit the same wall:"},
    {"id":"audience-sales-early-23","level":"early","profession":"sales","title":"Onboarding email: admin vs. everyone","scenario":"A new customer just signed. You're sending the kickoff email. The admin needs setup steps and credentials; the twelve end users need to know what's changing and why it helps them. Your draft mixes both into one confusing message.","task":"Write the 2-3 sentence version for the end users only.","tips":["End users need: what changes, when, and what's in it for them.","Setup instructions in a user email guarantee nobody reads either part.","One audience per message — send the admin a separate note."],"focus":["audience","clarity"]},
    {"id":"audience-sales-early-24","level":"early","profession":"sales","title":"The cold-call opener, recalibrated","scenario":"Your cold-call opener — 'Are you the person who handles marketing tools?' — worked on coordinators but flops with VPs, who hang up. A VP answers the phone expecting to be pitched and deciding in ten seconds whether you know their world.","task":"Write a 2-sentence VP-level opener that shows you know their problems.","tips":["VPs respond to peer-level observations about their business, not qualification questions.","Reference something true and specific about companies like theirs.","Earn the second sentence with the first."],"focus":["audience","impact"]},
    {"id":"audience-sales-early-25","level":"early","profession":"sales","title":"The newsletter blurb nobody asked for","scenario":"You're a marketing coordinator writing the product-update blurb for the customer newsletter. The draft from product reads: 'We've enhanced our data pipeline architecture for improved throughput.' Customers only notice one thing: reports that took minutes now load in seconds.","task":"Rewrite the blurb in 1-2 sentences from the reader's chair.","tips":["Describe the change as the moment the customer experiences it.","'Improved throughput' is internal pride; 'loads in seconds' is reader value.","If the reader can't feel it, cut it from the newsletter."],"focus":["audience","concision"],"placeholder":"Reports that used to take minutes now load in seconds."}
  ],
  "structure-that-carries": [
    {"id":"structure-sales-early-01","level":"early","profession":"sales","title":"The discovery notes dump","scenario":"Your discovery call covered budget, a competitor evaluation, a July deadline, two stakeholders you haven't met, and a wish list of features. Your recap draft is one long paragraph in the order things came up.","task":"Restructure the recap into a governing summary line plus 3 labeled groups.","tips":["One sentence up top: where the deal stands and the next step.","Group everything under 3 headers, e.g., Needs / Timeline / Open items.","Order by what the reader must act on, not by when it was said."],"focus":["structure","clarity"],"placeholder":"Strong fit, deciding by July — three things to move on."},
    {"id":"structure-sales-early-02","level":"early","profession":"sales","title":"The monthly review with one idea","scenario":"You're preparing your talking points for the monthly pipeline review. You have twelve scattered updates. Your manager remembers meetings that had one clear message, not twelve items.","task":"Write the governing sentence for your review plus the 3 buckets underneath it.","tips":["Find the one sentence that summarizes your month — everything else supports it.","Three buckets max: e.g., closing this month, building for next, needs help.","If an update fits no bucket, it probably doesn't belong in the meeting."],"focus":["structure","concision"],"placeholder":"My quarter comes down to landing two deals in the next three weeks."},
    {"id":"structure-sales-early-03","level":"early","profession":"sales","title":"SCQA for the proposal email","scenario":"You're writing the email that carries your proposal to a prospect whose team wastes hours reconciling spreadsheets. You have all the pieces but no frame: their situation, what's changed, the question they face, and your answer.","task":"Write a 4-sentence proposal opening using SCQA: situation, complication, question, answer.","tips":["Situation: their world as they'd describe it, one sentence.","Complication: what's changed or breaking — the reason to act now.","The answer is your proposal in one sentence, before any detail."],"focus":["structure","impact"]},
    {"id":"structure-sales-early-04","level":"early","profession":"sales","title":"Eight objections, three themes","scenario":"You collected eight objections from this month's lost and stalled deals: too expensive, no budget until Q3, IT worried about migration, 'we use spreadsheets fine,' switching costs, needs boss's sign-off, wrong timing, and data security. Your manager asked what's blocking deals.","task":"Group the eight into 3 named themes and state each theme in one line.","tips":["Look for the common root: several of these are really 'money,' several are 'risk of change.'","Name each theme in the customer's words, not category jargon.","A grouped answer is a strategy conversation; a list is a complaint."],"focus":["structure","clarity"],"placeholder":"They cluster into three themes: cost, switching risk, and timing."},
    {"id":"structure-sales-early-05","level":"early","profession":"sales","title":"PREP: 'Why should we pick you?'","scenario":"On a call, the prospect asks point-blank: 'Why should we pick you over the two other vendors we're evaluating?' You know the answer but tend to ramble through features until you find a landing spot.","task":"Write your spoken answer using PREP: point, reason, example, point restated — 4-5 sentences.","tips":["Point first: the one difference that matters for them.","One reason, one concrete customer example — not three of each.","Land back on the point; don't trail off into features."],"focus":["structure","impact"]},
    {"id":"structure-sales-early-06","level":"early","profession":"sales","title":"The campaign recap skeleton","scenario":"Your email campaign wrapped: 18% reply rate on sequence A, 6% on sequence B, most replies from the operations-manager segment, and the case-study email outperformed everything. Your recap draft mixes results, explanations, and ideas at random.","task":"Structure the recap as: one headline finding, then Results / Why / Next as three short sections.","tips":["The headline is the single thing you'd keep if you could keep one.","Separate what happened from why you think it happened.","'Next' should follow logically from 'Why' — that's the test of the structure."],"focus":["structure","precision"]},
    {"id":"structure-sales-early-07","level":"early","profession":"sales","title":"Three threads, one email","scenario":"You owe a prospect answers on three unrelated things: the revised pricing, a security question from her IT team, and scheduling the stakeholder demo. Your draft weaves all three through four paragraphs.","task":"Restructure into an email with a one-line summary and three clearly separated blocks.","tips":["Open by naming the three items so the reader can navigate.","One block per thread, with a bolded or labeled first line each.","Put the item needing her action first."],"focus":["structure","clarity"],"placeholder":"Three updates: revised pricing, your IT team's security answer, and demo scheduling."},
    {"id":"structure-sales-early-08","level":"early","profession":"sales","title":"The event lead report","scenario":"You came back from the trade show with 74 badge scans. Some are hot prospects who asked for meetings, some are competitors and students, and the rest are lukewarm maybes. Your report draft lists all 74 in scan order.","task":"Write the report's opening: one summary line plus a 3-tier grouping with counts and next actions.","tips":["Group by what should happen next, not by when you met them.","Each tier gets a count and one action: call this week / nurture / discard.","The summary line is the ROI answer your manager actually wants."],"focus":["structure","precision"],"placeholder":"74 scans break into 12 meeting-ready, 31 nurture, 31 not a fit."},
    {"id":"structure-sales-early-09","level":"early","profession":"sales","title":"The demo agenda that mirrors their priorities","scenario":"In discovery, the prospect named three priorities: cutting manual data entry, visibility for her director, and getting the team onboarded fast. Your demo plan is currently organized by product module, the way you learned it.","task":"Write a 3-part demo agenda where each part is named after one of her priorities.","tips":["Her three priorities are your three sections — in her order of importance.","Name each section in her words from the call.","Modules are your map, not hers; hide the seams."],"focus":["structure","audience"]},
    {"id":"structure-sales-early-10","level":"early","profession":"sales","title":"Call notes a stranger could use","scenario":"Your CRM notes from today's call read: 'good call, likes it, budget maybe Q3, loop in Dan, send pricing.' If you're out sick next week, whoever covers this deal will be lost.","task":"Rewrite the notes with a structure anyone could act on: outcome, key facts, next steps with owners and dates.","tips":["First line: the call's outcome in one sentence.","Facts and quotes in one block; commitments in another.","Every next step gets an owner and a date — including the prospect's."],"focus":["structure","precision"],"placeholder":"Outcome: verbal interest, pricing requested, decision gated on Dan (IT)."},
    {"id":"structure-sales-early-11","level":"early","profession":"sales","title":"The handoff doc skeleton","scenario":"You're building your first handoff doc for a closed deal moving to customer success. You know everything about the account; CS knows nothing. You start typing chronologically from the first cold call.","task":"Define the doc's structure: write its 4 section headers and one line of what belongs in each.","tips":["Structure by CS's questions: who are they, what did they buy and why, what was promised, what happens next.","Chronology is how you lived it, not how CS needs it.","'Promises made' deserves its own section — that's where handoffs fail."],"focus":["structure","audience"]},
    {"id":"structure-sales-early-12","level":"early","profession":"sales","title":"The comparison the prospect can use","scenario":"A prospect asked how you compare to CompetitorX. You have ten scattered points — some pricing, some features, some support. She'll forward whatever you send to her boss.","task":"Structure the comparison as 3 dimensions that matter to her, one verdict line each.","tips":["Pick the 3 dimensions she cares about, not the 10 you can win.","One honest line per dimension — concede a small point to earn trust.","End with the summary judgment you want her boss to repeat."],"focus":["structure","audience"]},
    {"id":"structure-sales-early-13","level":"early","profession":"sales","title":"SCQA for the tooling pitch","scenario":"You want your manager to buy the team a $150/month data-enrichment tool. Your draft opens with the tool's features. Your manager needs to feel the problem before hearing the solution.","task":"Write the pitch as SCQA in 4 sentences: current state, what's breaking, the question, your answer.","tips":["Situation: how the team prospects today, neutrally stated.","Complication: the hours lost and bad data — make it cost something.","Your ask lands as the natural answer to the question you framed."],"focus":["structure","impact"],"placeholder":"Each of us prospects from raw lists we clean by hand."},
    {"id":"structure-sales-early-14","level":"early","profession":"sales","title":"PREP: 'Why did it slip?'","scenario":"In pipeline review, your manager asks why the Fairview deal slipped a month. The true answer has a point (legal review), a reason, and an example — but under pressure you tend to narrate the whole deal history.","task":"Write the spoken answer in PREP form, 3-4 sentences.","tips":["Point: 'Legal review added three weeks — new close date is the 15th.'","One supporting fact, not the full negotiation saga.","Restate the point with what you're doing to hold the new date."],"focus":["structure","concision"]},
    {"id":"structure-sales-early-15","level":"early","profession":"sales","title":"Ten loss reasons, one message to product","scenario":"You reviewed your last ten lost deals and jotted a reason for each. Reading the list, you notice several trace back to a missing integration, several to price, and a couple to slow follow-up. Product asked for 'anything useful from lost deals.'","task":"Write a 4-sentence summary: governing insight first, then the grouped themes with counts.","tips":["Lead with the biggest actionable theme, not the full inventory.","Counts turn anecdotes into evidence: '4 of 10 cited the missing integration.'","Flag which theme product can fix versus which is pricing's problem."],"focus":["structure","precision"],"placeholder":"The clearest pattern in our last 10 losses: 4 cited the missing QuickBooks integration."},
    {"id":"structure-sales-early-16","level":"early","profession":"sales","title":"The sequence rationale","scenario":"You built a new 5-touch outreach sequence and your manager asked you to walk the team through it. Your draft explains each email in order. The team needs the logic before the touches: who it targets, what it argues, why this order.","task":"Write the walkthrough's structure: one governing idea, then 3 sections (audience, argument, sequence logic).","tips":["Start with the strategy in one sentence; the five emails are just its execution.","Explain why touch 3 follows touch 2 — the order is the design.","If the logic is clear, the team can improvise; if not, they'll copy blindly."],"focus":["structure","clarity"]},
    {"id":"structure-sales-early-17","level":"early","profession":"sales","title":"The objection-handling one-pager","scenario":"Your manager asked you to draft an objection-handling cheat sheet for the two new SDRs. You have fourteen objections and responses in a running doc, unordered. New reps freeze mid-call trying to find the right one.","task":"Design the one-pager's structure: 3-4 groups with names, and state which objections go where.","tips":["Group by the objection's root: price, timing, trust, status quo.","Name groups by what the rep hears, so lookup is instant mid-call.","Within each group, put the most common objection first."],"focus":["structure","audience"]},
    {"id":"structure-sales-early-18","level":"early","profession":"sales","title":"Five questions, one readable reply","scenario":"A prospect's email asks five questions: seat pricing, contract length, onboarding time, data export, and whether you support SSO. Your reply draft answers them in one dense paragraph.","task":"Restructure the reply: one-line summary up top, then the five answers scannable at a glance.","tips":["Mirror her questions in her order — she'll check them off.","One line per answer; link out for depth.","The summary line up top: 'Short version: yes to all five, details below.'"],"focus":["structure","concision"],"placeholder":"Short answers to all five below — the headline: yes on SSO and export."},
    {"id":"structure-sales-early-19","level":"early","profession":"sales","title":"The renewal proposal's governing idea","scenario":"Your renewal proposal for a customer includes usage stats, a new module pitch, a small price increase, and multi-year options. Drafted as four equal sections, it reads like four separate emails.","task":"Write the one governing sentence that unifies the proposal, then name the 3 sections that support it.","tips":["Find the idea that makes all four parts one argument, e.g., 'lock in what's working.'","Every section should visibly serve the governing line.","If a section doesn't support the idea, it's a different email."],"focus":["structure","impact"]},
    {"id":"structure-sales-early-20","level":"early","profession":"sales","title":"The weekly update template","scenario":"Your manager asked you to send a weekly update 'in whatever format works.' Your first one was stream-of-consciousness and she asked clarifying questions about all of it. You want a structure you can repeat every Friday.","task":"Write this week's update using three fixed buckets: Closed/Won, Moving, Stuck (with asks).","tips":["Fixed buckets mean she knows where to look before she opens it.","'Stuck' items must carry an ask — that's why she reads them.","Two lines per bucket; the update should fit on one screen."],"focus":["structure","concision"],"placeholder":"Closed: Meridian ($9K). Moving: 3 deals on track. Stuck: 1 — need your help."},
    {"id":"structure-sales-early-21","level":"early","profession":"sales","title":"Conference notes into an action memo","scenario":"You spent two days at an industry conference: eleven pages of notes on competitor announcements, three product ideas, six prospect conversations, and a pricing rumor. Your manager asked, 'anything we should act on?'","task":"Write the memo's opening line and 3 grouped sections, action-first.","tips":["Lead with the one thing that needs a decision this week.","Group as: act now / worth watching / FYI.","Eleven pages of notes is your archive, not your memo."],"focus":["structure","concision"]},
    {"id":"structure-sales-early-22","level":"early","profession":"sales","title":"PREP: 'Is this lead worth it?'","scenario":"An AE pings you: 'Your lead from the webinar — worth my time?' You believe it is: right industry, stated pain, budget owner attending. You tend to answer with the whole call transcript.","task":"Write the spoken PREP answer in 3-4 sentences.","tips":["Point first: 'Yes — take the meeting.'","Reason: the two qualification facts that matter most.","Example: the quote from the lead that proves the pain is real."],"focus":["structure","concision"],"placeholder":"Yes — take the meeting."},
    {"id":"structure-sales-early-23","level":"early","profession":"sales","title":"SCQA for the partner pitch","scenario":"You're pitching a webinar co-host idea to a partner company's marketing lead. Cold, the ask sounds like work for them. Framed right, it answers a problem they already have: their audience is asking about exactly what you sell.","task":"Write the pitch as SCQA in 4-5 sentences ending in the co-host ask.","tips":["Situation and complication should be about their audience, not your pipeline.","The question frames co-hosting as the obvious answer.","End with a specific, small ask: one webinar, one date range."],"focus":["structure","audience"]},
    {"id":"structure-sales-early-24","level":"early","profession":"sales","title":"The pricing explanation that doesn't confuse","scenario":"A prospect asked you to 'explain the pricing.' You have three tiers, per-seat rates, an onboarding fee, and a discount for annual. Listed flat, it reads like a menu with no waiter.","task":"Structure the explanation: what pricing is based on (1 line), the options (grouped), then your recommendation for them.","tips":["Start with the model in one sentence: 'You pay per seat, annually.'","Group the tiers around her stated team size — irrelevant tiers get one line.","End with a recommendation; a menu without guidance stalls deals."],"focus":["structure","clarity"],"placeholder":"Pricing is simple: per seat, billed annually. For your team of 12, here's how it looks."},
    {"id":"structure-sales-early-25","level":"early","profession":"sales","title":"Keep, fix, kill","scenario":"You're a marketing coordinator reviewing quarter-end results across five channels: the newsletter performs, paid social burns budget with nothing to show, webinars work but exhaust the team, the blog is flat, and the podcast sponsorship is unmeasured. Your manager wants a recommendation, not a data dump.","task":"Write the review structured as Keep / Fix / Kill, one governing line up top, one line per channel.","tips":["The three verbs are your buckets — every channel gets exactly one.","Governing line first: the single shift you're recommending this quarter.","'Unmeasured' is a finding, not a shrug — put it in Fix with a plan."],"focus":["structure","impact"]}
  ],
  "cut-to-the-bone": [
    {"id":"concise-sales-early-01","level":"early","profession":"sales","title":"The cold email nobody finishes","scenario":"Your cold email runs 220 words with three paragraphs of context before the ask. Prospects skim the first two lines and delete. Your reply rate is telling you the email is too long.","task":"Cut the email to under 75 words while keeping the hook and the ask.","tips":["Delete every sentence that doesn't move toward the ask.","One idea, one ask, one call to action.","If a line only makes you feel thorough, cut it."],"focus":["concision","impact"]},
    {"id":"concise-sales-early-02","level":"early","profession":"sales","title":"Hedges in the follow-up","scenario":"Your follow-up reads: 'I just wanted to quickly reach out and see if maybe you might possibly have a little time to perhaps chat sometime soon.' Every qualifier makes you sound less sure you deserve the meeting.","task":"Rewrite the sentence with every hedge removed.","tips":["Cut 'just,' 'quickly,' 'maybe,' 'might,' 'possibly,' 'perhaps,' 'a little,' 'sometime.'","Ask directly: a time, a length, a reason.","Confidence reads as competence to a busy prospect."],"focus":["concision","impact"],"placeholder":"Do you have 15 minutes Thursday to see how we cut your reporting time in half?"},
    {"id":"concise-sales-early-03","level":"early","profession":"sales","title":"The recap that repeats itself","scenario":"Your discovery recap says the same thing three ways: 'You mentioned that your current process is manual and done by hand, which takes a lot of time and is very time-consuming.' The reader gets it the first time.","task":"Compress the redundant sentence to one clean clause.","tips":["'Manual and done by hand' is one idea said twice — pick one.","'Takes a lot of time and is very time-consuming' is pure repetition.","Say it once, precisely, and move on."],"focus":["concision","precision"],"placeholder":"Your intake is still manual, which eats about a day a week."},
    {"id":"concise-sales-early-04","level":"early","profession":"sales","title":"Nominalizations in the proposal","scenario":"Your proposal reads: 'The implementation of the solution will result in the reduction of processing times and the improvement of accuracy.' Buried inside are simple verbs dressed up as nouns.","task":"Rewrite the sentence using active verbs instead of noun-heavy phrases.","tips":["'The reduction of' becomes 'reduces'; 'the improvement of' becomes 'improves.'","Verbs move; nominalizations sit still.","Shorter and more concrete in one move."],"focus":["concision","clarity"],"placeholder":"This cuts processing time and improves accuracy."},
    {"id":"concise-sales-early-05","level":"early","profession":"sales","title":"The meta-commentary opener","scenario":"Your email to a prospect opens: 'I wanted to write to you today to let you know that I'm reaching out because I think there might be an opportunity for us to work together.' Four clauses of throat-clearing before any content.","task":"Cut the meta-commentary and start with the actual point.","tips":["'I wanted to write to let you know that' is zero information — delete it.","Announcing that you're reaching out is not reaching out.","Start where the reader's interest starts."],"focus":["concision","impact"]},
    {"id":"concise-sales-early-06","level":"early","profession":"sales","title":"The Slack update that scrolls","scenario":"Your pipeline update to your manager is eight lines of narrative for what amounts to three facts: one deal closed, one slipped, one needs help. She has to read all eight to extract them.","task":"Cut the update to three lines, one fact each.","tips":["One line per deal, verb first.","Drop the connective narration between facts.","She should get all three in a five-second glance."],"focus":["concision","structure"],"placeholder":"Closed: Meridian $9K. Slipped: Fairview to next month. Need help: Delta pricing."},
    {"id":"concise-sales-early-07","level":"early","profession":"sales","title":"Redundant pairs everywhere","scenario":"Your objection-handling reply is full of doubled words: 'first and foremost,' 'each and every,' 'full and complete,' 'true and accurate.' They add length and a whiff of boilerplate, not substance.","task":"Rewrite the reply removing every redundant pair down to one word.","tips":["Pick the stronger half of each pair and drop the other.","Doubled words signal filler to a sharp reader.","Concise reads as candid; padded reads as sales-y."],"focus":["concision","precision"]},
    {"id":"concise-sales-early-08","level":"early","profession":"sales","title":"The voicemail that rambles","scenario":"Your 45-second voicemail spends 30 seconds on preamble — who you are, how you found them, hoping they're well — before the 15 seconds that matter. Most listeners hang up before the point.","task":"Cut the voicemail to 20 seconds: reason, value, callback.","tips":["Open with why you're calling, in one sentence.","Cut the pleasantries entirely — this is a voicemail, not a chat.","Name and number last, slow and clear."],"focus":["concision","impact"]},
    {"id":"concise-sales-early-09","level":"early","profession":"sales","title":"The over-explained feature","scenario":"A prospect asked a simple question and you answered with a 150-word paragraph covering every edge case and caveat. She asked whether you export to CSV; the answer is yes.","task":"Rewrite the answer to lead with 'yes' and add only what she needs.","tips":["Answer the question asked before volunteering the caveats.","One relevant detail beats five defensive ones.","She can ask a follow-up; you don't have to pre-empt all of them."],"focus":["concision","clarity"],"placeholder":"Yes — one-click CSV export, and Excel and Google Sheets too."},
    {"id":"concise-sales-early-10","level":"early","profession":"sales","title":"Filler in the demo intro","scenario":"You open every demo with two minutes of 'a little bit about us, our history, our mission, some logos of customers you might recognize.' The prospect booked 30 minutes to see if it solves her problem, and you're burning them.","task":"Cut the demo intro to 20 seconds that earn the right to keep going.","tips":["One sentence of credibility, then straight to her problem.","Company history is your comfort, not her need.","Every minute of intro is a minute not solving her problem."],"focus":["concision","audience"]},
    {"id":"concise-sales-early-11","level":"early","profession":"sales","title":"The email with three asks","scenario":"Your email asks the prospect to review the proposal, schedule a demo, loop in her IT lead, and confirm budget — all in one message. Faced with four asks, she does none.","task":"Cut to the single most important ask and remove the rest.","tips":["Pick the one action that unblocks everything else.","Multiple asks compete and cancel out.","Save the others for after she says yes to the first."],"focus":["concision","impact"]},
    {"id":"concise-sales-early-12","level":"early","profession":"sales","title":"The bloated subject line","scenario":"Your email subject reads: 'Following up on our conversation from last week regarding the potential opportunity to help your team.' It gets truncated in her inbox and says nothing before the cutoff.","task":"Write a subject line under 6 words that earns the open.","tips":["Front-load the one word that makes her curious or reminds her who you are.","'Following up' is the weakest possible opener.","The first three words are all she sees on mobile."],"focus":["concision","impact"],"placeholder":"Your reporting time — cut in half"},
    {"id":"concise-sales-early-13","level":"early","profession":"sales","title":"Qualifiers in the price answer","scenario":"Asked about price, you write: 'It sort of depends on a number of factors, but roughly speaking it's generally around somewhere in the range of $12K, give or take.' Every hedge makes the number sound negotiable and you sound unsure.","task":"State the price in one clean sentence.","tips":["Give the number without the cloud of qualifiers.","One honest caveat is fine; five make you sound evasive.","Firm numbers close; fuzzy ones stall."],"focus":["concision","precision"],"placeholder":"The 20-seat plan is $12,000 a year, billed annually."},
    {"id":"concise-sales-early-14","level":"early","profession":"sales","title":"The recap of the recap","scenario":"Your post-call email summarizes the call, then restates the summary in a 'to recap' paragraph, then adds a 'in short' line. Three summaries of the same 40-minute call.","task":"Keep one summary and cut the other two.","tips":["Decide which of the three is tightest and delete the rest.","Repetition doesn't add emphasis in writing — it adds length.","One clear summary respects the reader's time."],"focus":["concision","structure"]},
    {"id":"concise-sales-early-15","level":"early","profession":"sales","title":"The over-hedged forecast","scenario":"Your forecast note reads: 'I think this could possibly maybe close this month, but it's hard to say, we'll see how it goes, fingers crossed.' Your manager can't plan around that.","task":"Rewrite the forecast as one committed line with a real probability.","tips":["Pick a stance: commit, best-case, or long-shot — and say which.","'We'll see' is not a forecast.","A wrong-but-clear call is more useful than a hedge."],"focus":["concision","precision"],"placeholder":"Committing this month — 80% confidence, signature expected by the 25th."},
    {"id":"concise-sales-early-16","level":"early","profession":"sales","title":"The LinkedIn message that overstays","scenario":"Your LinkedIn connection note is 300 characters of your background and why you admire her work. She accepts or ignores based on the first line, and yours buries the reason in paragraph two.","task":"Cut the note to under 40 words with the relevance up front.","tips":["One specific, true reason you're connecting — first.","Drop the flattery; it reads as a lead-in to a pitch.","Short and relevant beats long and warm."],"focus":["concision","audience"]},
    {"id":"concise-sales-early-17","level":"early","profession":"sales","title":"Weasel words in the case study ask","scenario":"You're asking a customer to be a reference and you've wrapped the ask in so much softening — 'no pressure at all, only if you have time, totally understand if not, absolutely no worries either way' — that the actual request is hard to find.","task":"Rewrite the ask: one clear request, one genuine out, nothing more.","tips":["Over-apologizing for the ask makes it awkward to say yes.","One 'no pressure' is warmth; four is anxiety.","Respect her enough to ask plainly."],"focus":["concision","clarity"],"placeholder":"Would you be open to a 20-minute reference call next month? No problem at all if the timing's off."},
    {"id":"concise-sales-early-18","level":"early","profession":"sales","title":"The campaign recap with three throat-clears","scenario":"Your campaign recap opens: 'As you know, we've been running our Q2 email campaign, and I wanted to take a moment to share some of the results that we've seen so far.' The reader knew all of that; the results start in sentence three.","task":"Cut to the results in the first sentence.","tips":["'As you know' means you can delete what follows.","'I wanted to take a moment to share' is a throat-clear.","Start with the number."],"focus":["concision","impact"],"placeholder":"The Q2 campaign drove 42 qualified leads — double target."},
    {"id":"concise-sales-early-19","level":"early","profession":"sales","title":"The event invite that lists everything","scenario":"Your event invite lists the venue history, the full agenda, seven speaker bios, parking details, and the dress code — before the one line that matters: what the prospect will learn and why to come.","task":"Cut the invite body to under 60 words that sell the reason to attend.","tips":["Logistics go at the bottom or in a link, not the pitch.","Lead with the takeaway, not the schedule.","If it doesn't help them decide to come, it's not in the invite."],"focus":["concision","audience"]},
    {"id":"concise-sales-early-20","level":"early","profession":"sales","title":"The handoff note that over-narrates","scenario":"Your CS handoff note tells the deal as a story: 'It all started when I found them on LinkedIn, and after a few emails back and forth, we finally got a call, and things went well from there...' CS needs facts, not a narrative arc.","task":"Cut the narrative and list the four facts CS needs.","tips":["CS wants: goal, what they bought, promises made, go-live date.","The origin story is irrelevant to onboarding them.","Facts in a list beat a story in a paragraph."],"focus":["concision","structure"]},
    {"id":"concise-sales-early-21","level":"early","profession":"sales","title":"The demo request buried in courtesy","scenario":"Your email to a sales engineer runs: 'I hope this finds you well and that you're not too swamped, and I completely understand if you're busy, but I was wondering if there's any chance you might be able to possibly help me out with a demo.' The ask is one clause in a fog of apology.","task":"Rewrite as a direct, respectful ask in two sentences.","tips":["Colleagues appreciate a clear ask more than elaborate deference.","State what you need, when, and why it matters.","One line of context is enough to make it easy to say yes."],"focus":["concision","clarity"],"placeholder":"Can you join Thursday's demo, 2-2:45? The prospect has deep API questions I can't field alone."},
    {"id":"concise-sales-early-22","level":"early","profession":"sales","title":"Adjective pile-up","scenario":"Your product description reads: 'a powerful, robust, comprehensive, best-in-class, cutting-edge, enterprise-grade platform.' Six adjectives that each mean less because the others are there.","task":"Rewrite the phrase with at most one adjective and one concrete claim.","tips":["Stacked superlatives cancel each other out.","Replace the adjectives with one fact the reader can verify.","Specifics persuade; adjectives decorate."],"focus":["concision","precision"],"placeholder":"A platform that processes 10,000 orders a day without a dropped record."},
    {"id":"concise-sales-early-23","level":"early","profession":"sales","title":"The over-long objection rebuttal","scenario":"A prospect said 'too expensive.' Your reply is 200 words defending the price from every angle. The length signals defensiveness and gives her more to argue with.","task":"Cut the rebuttal to three sentences: acknowledge, reframe, evidence.","tips":["A short, confident reply reads as more sure of the value.","One reframe and one proof point beat five.","The longer you argue price, the more it sounds like a problem."],"focus":["concision","impact"]},
    {"id":"concise-sales-early-24","level":"early","profession":"sales","title":"The team-update monologue","scenario":"In Monday's stand-up, your verbal update runs three minutes covering every email and call since Friday. The team's attention is gone by minute one, and your two real updates are lost.","task":"Cut your spoken update to two sentences: what moved, what you need.","tips":["Stand-up is headlines, not a diary.","Say the change and the ask; skip the play-by-play.","If nothing changed and you need nothing, pass."],"focus":["concision","structure"],"placeholder":"Northgate moved to contract; I need legal's eyes on the redlines by Wednesday."},
    {"id":"concise-sales-early-25","level":"early","profession":"sales","title":"The signature that's a paragraph","scenario":"Your email signature includes your name, three titles, four phone numbers, two office addresses, a calendar link, a quote, and a legal disclaimer. On mobile it's longer than most of your emails.","task":"Cut the signature to four essential lines.","tips":["Keep name, one relevant title, one contact method, one link.","The inspirational quote works against a professional tone.","A bloated signature dilutes the message above it."],"focus":["concision","clarity"]}
  ],
  "precision-and-evidence": [
    {"id":"precision-sales-early-01","level":"early","profession":"sales","title":"'A lot of time' means what?","scenario":"Your cold email claims 'our customers save a ton of time and see huge improvements in efficiency.' A skeptical operations manager reads 'ton' and 'huge' as sales inflation and moves on.","task":"Rewrite the claim with a specific number and where it comes from.","tips":["Replace 'a ton' with a figure: hours per week, percent reduction.","Attribute it: 'customers like [X] saw...' beats an unsourced boast.","A precise, modest number outsells a vague, grand one."],"focus":["precision","impact"],"placeholder":"Teams your size cut invoice processing from 12 hours a week to about 3."},
    {"id":"precision-sales-early-02","level":"early","profession":"sales","title":"The vague pipeline answer","scenario":"Your manager asks how the Meridian deal is going and you say 'really well, they seem pretty interested and I think it's moving in the right direction.' None of that helps her forecast.","task":"Rewrite the answer with concrete evidence of stage and momentum.","tips":["Name the stage, the last commitment they made, and the next step with a date.","'Seems interested' is your read; 'agreed to a demo with their VP' is evidence.","Replace feelings with facts your manager can bank on."],"focus":["precision","structure"],"placeholder":"Meridian's at proposal stage — VP joins the demo Thursday, deciding by month-end."},
    {"id":"precision-sales-early-03","level":"early","profession":"sales","title":"So what, from the campaign data","scenario":"Your campaign report states: '2,400 emails sent, 22% open rate, 4% click rate, 15 replies.' You've given the data but not the insight — your manager still has to figure out what it means.","task":"Add the one-sentence insight: what these numbers mean and what to do next.","tips":["Data is What; your manager needs So What and Now What.","Compare to benchmark or last month to make the number mean something.","End with the action the numbers argue for."],"focus":["precision","impact"],"placeholder":"Replies came almost entirely from the ops-manager segment — we should shift the next send toward them."},
    {"id":"precision-sales-early-04","level":"early","profession":"sales","title":"The unquantified ROI claim","scenario":"Your proposal says the tool 'pays for itself quickly.' The CFO reviewing it wants to see the arithmetic, not the assurance. Vague payback claims get flagged, not approved.","task":"Rewrite the claim showing the payback math in one or two sentences.","tips":["Show the inputs: cost, savings per month, and the resulting payback period.","'Quickly' is an opinion; '4.5 months' is a case.","Round honestly — a defensible estimate beats a rosy one."],"focus":["precision","impact"],"placeholder":"At $12K a year against roughly $2,700/month in recovered time, it pays back in about 4.5 months."},
    {"id":"precision-sales-early-05","level":"early","profession":"sales","title":"'Soon' isn't a date","scenario":"Your follow-up email says you'll 'circle back soon' and the prospect will 'hear from the team shortly.' Neither of you now has a real commitment, and the deal drifts.","task":"Rewrite the two vague timeframes as specific dates and owners.","tips":["'Soon' becomes 'by Thursday'; 'shortly' becomes 'within two business days.'","Name who does what, not just when.","Precise commitments are the ones that actually happen."],"focus":["precision","clarity"],"placeholder":"I'll send the revised proposal by Wednesday; our SE will confirm the security answers by Friday."},
    {"id":"precision-sales-early-06","level":"early","profession":"sales","title":"The skeptic-test objection reply","scenario":"A prospect says your product 'probably won't scale to our volume.' Your draft reply insists 'it scales great, don't worry.' A skeptic hears bluster, not proof.","task":"Rewrite the reply with a specific, verifiable scale claim.","tips":["Give a number that beats her volume, from a real customer or benchmark.","Offer proof she can check: a reference, a doc, a test.","'Don't worry' is exactly what someone with no evidence says."],"focus":["precision","impact"],"placeholder":"We handle 50,000 orders/day for [customer]; at your 8,000/day you have headroom to spare."},
    {"id":"precision-sales-early-07","level":"early","profession":"sales","title":"The results email with no baseline","scenario":"You report to a customer: 'Your team logged 4,000 orders this quarter and error rates improved.' Without a before-number, 'improved' is unmeasurable and unpersuasive at renewal time.","task":"Rewrite with the baseline so the improvement is concrete.","tips":["Every 'improved' needs a from-X-to-Y.","The delta is the value story — spell it out.","A number without a baseline is decoration."],"focus":["precision","impact"],"placeholder":"Order errors dropped from 3.1% to 1.9% this quarter — about a third fewer."},
    {"id":"precision-sales-early-08","level":"early","profession":"sales","title":"'Most' and 'many' in the pitch","scenario":"Your pitch deck says 'most companies in your space struggle with this' and 'many of our customers see fast results.' The buyer's analyst will ask 'how many?' and you won't have a number.","task":"Rewrite both phrases with real figures or drop the claim.","tips":["'Most' is a percentage you should be able to name.","If you can't source the number, cut the claim rather than fake precision.","A sourced 'three of the four largest' beats an airy 'most.'"],"focus":["precision","clarity"]},
    {"id":"precision-sales-early-09","level":"early","profession":"sales","title":"The forecast confidence, quantified","scenario":"Your manager asks how sure you are about a deal closing this month. You say 'pretty confident.' She needs a number she can weight in the team forecast.","task":"State your confidence as a percentage with the two facts driving it.","tips":["Attach a number: 70%, 90% — and say what would change it.","Ground the number in evidence, not gut alone.","A calibrated number lets her plan; 'pretty confident' doesn't."],"focus":["precision","structure"],"placeholder":"75% — verbal yes from the buyer, but still waiting on procurement sign-off."},
    {"id":"precision-sales-early-10","level":"early","profession":"sales","title":"The demo claim you can't back","scenario":"Mid-demo you say 'this basically eliminates manual data entry.' The prospect asks 'completely?' and you have to walk it back to 'well, mostly.' The overclaim cost you credibility.","task":"Rewrite the claim to be precise and defensible from the start.","tips":["Say what it actually does: 'cuts manual entry by about 80%.'","Precision up front prevents the embarrassing walk-back.","Under-promise slightly; let the demo over-deliver."],"focus":["precision","impact"],"placeholder":"This handles about 80% of the entry automatically — the exceptions still route to a person."},
    {"id":"precision-sales-early-11","level":"early","profession":"sales","title":"The event ROI with no math","scenario":"You're justifying the trade show to your manager: 'It was definitely worth it, lots of good conversations and strong interest.' She's deciding whether to fund it next year and needs numbers.","task":"Rewrite the assessment with the pipeline math from the event.","tips":["Convert 'good conversations' into scans, meetings booked, and pipeline dollars.","Compare against the cost to show real ROI.","'Strong interest' can't be budgeted against."],"focus":["precision","impact"],"placeholder":"74 scans, 12 meetings booked, ~$140K pipeline against a $9K cost."},
    {"id":"precision-sales-early-12","level":"early","profession":"sales","title":"'Industry-leading' means nothing","scenario":"Your one-pager describes the product as 'industry-leading, award-winning, and trusted by top companies.' A buyer reads three empty superlatives and looks for the actual differentiator.","task":"Replace the three superlatives with one specific, checkable proof point.","tips":["'Trusted by top companies' — name one and what they do with it.","Awards mean little; a concrete outcome means a lot.","One verifiable fact outweighs three self-awarded labels."],"focus":["precision","impact"],"placeholder":"[Named customer] runs their entire 40-branch operation on it — reference available."},
    {"id":"precision-sales-early-13","level":"early","profession":"sales","title":"The status update that hides the risk","scenario":"You tell your manager a deal is 'on track,' but there's a real blocker: the buyer's budget approval isn't confirmed. 'On track' hides the one thing she'd want to know.","task":"Rewrite the update to state the deal's status and the specific open risk.","tips":["'On track' should survive the skeptic test — yours doesn't.","Name the exact blocker and what closes it.","Honest risk-flagging builds more trust than optimism."],"focus":["precision","structure"],"placeholder":"On track on the buyer's side; the one open risk is budget sign-off, expected next week."},
    {"id":"precision-sales-early-14","level":"early","profession":"sales","title":"The vague competitive claim","scenario":"A prospect asks how you beat CompetitorX and you say 'we're faster and more reliable.' She's heard every vendor say that. Without specifics it's noise.","task":"Rewrite with one measurable, verifiable comparison.","tips":["'Faster' needs a number and a benchmark they can trust.","Concede where you're even — it makes your real edge believable.","A specific, checkable claim survives her diligence call."],"focus":["precision","impact"],"placeholder":"Their sync runs nightly; ours runs hourly — so your dashboards are never a day behind."},
    {"id":"precision-sales-early-15","level":"early","profession":"sales","title":"Data with no takeaway for the AE","scenario":"You hand an AE a lead with a note: 'downloaded the pricing guide, attended the webinar, opened three emails, visited the site twice.' Accurate, but you've left the AE to infer whether it's hot.","task":"Add the one-line read: what the signals add up to and how to open.","tips":["Turn the activity log into a verdict: high intent, budget-owner, ready for a call.","Tell the AE the single best hook to lead with.","Signals without a synthesis waste the AE's time."],"focus":["precision","audience"],"placeholder":"High intent — pricing-guide download plus webinar attendance says she's evaluating now; lead with the ROI angle."},
    {"id":"precision-sales-early-16","level":"early","profession":"sales","title":"The 'we'll get back to you' with no substance","scenario":"A prospect asked whether you integrate with their ERP. You don't know, so you wrote 'let me check and get back to you.' Two weeks later you still haven't, and precision on the follow-through would have kept the deal warm.","task":"Rewrite the holding reply so it commits to a specific answer by a specific time.","tips":["An honest 'I don't know yet' is fine — pair it with a date.","Name who you're checking with and when you'll report back.","Vague promises to follow up are how deals go cold."],"focus":["precision","clarity"],"placeholder":"I don't have the ERP answer yet — checking with our solutions team and I'll confirm by Thursday."},
    {"id":"precision-sales-early-17","level":"early","profession":"sales","title":"The renewal case built on adjectives","scenario":"Your renewal email tells the customer the past year was 'a great success' and the 'partnership has been really valuable.' At renewal, feelings don't justify the invoice — usage does.","task":"Rewrite the renewal opener grounded in their actual usage numbers.","tips":["Replace 'great success' with what they did: orders processed, hours saved, errors cut.","Their own data is the strongest renewal argument.","'Valuable' is your word; a number is theirs."],"focus":["precision","impact"],"placeholder":"This year your team ran 4,000 orders through the platform and cut errors by a third —"},
    {"id":"precision-sales-early-18","level":"early","profession":"sales","title":"The A/B result with no significance","scenario":"You report that subject line A 'did way better' than B. It got 24% opens vs. 22% on a 200-person send. That gap is within noise, but your recap presents it as a clear winner.","task":"Rewrite the finding honestly, noting the sample and whether the gap is meaningful.","tips":["A 2-point gap on 200 sends isn't a 'clear winner.'","State the sample size so the reader can judge the finding.","Overstating small results erodes trust in your bigger ones."],"focus":["precision","clarity"],"placeholder":"A edged B, 24% to 22%, but on only 200 sends that's within noise — worth a bigger test before we call it."},
    {"id":"precision-sales-early-19","level":"early","profession":"sales","title":"The 'huge opportunity' with no sizing","scenario":"You tell your manager an account is a 'huge opportunity' and 'could be massive for us.' She asks 'how big?' and you realize you never sized it.","task":"Rewrite the pitch with a concrete deal-size estimate and the basis for it.","tips":["Estimate the dollars: seats × price, or their spend on the problem today.","Show your reasoning so the number is credible, not plucked.","'Huge' can't be forecast; '$60K expansion' can."],"focus":["precision","impact"],"placeholder":"Roughly a $60K opportunity — 100 seats at our team rate, based on their headcount."},
    {"id":"precision-sales-early-20","level":"early","profession":"sales","title":"The demo recap that overstates agreement","scenario":"Your recap says the prospect 'loved it and is ready to move forward.' What actually happened: she was positive but needs to check with two colleagues. Your inflated recap will collide with reality next week.","task":"Rewrite the recap to state precisely what was and wasn't agreed.","tips":["Separate her enthusiasm from her commitment.","Name the exact next step and what's still open.","An accurate recap protects you when the deal is scrutinized."],"focus":["precision","structure"],"placeholder":"Strong positive signal; she's championing it internally but needs sign-off from IT and finance before committing."},
    {"id":"precision-sales-early-21","level":"early","profession":"sales","title":"The pricing objection with a made-up stat","scenario":"To counter a price objection you almost write 'studies show teams like yours waste 40% of their time on manual work.' You don't actually have that source, and a sharp buyer will ask for it.","task":"Rewrite the point using only a claim you can stand behind.","tips":["If you can't cite it, don't quote a fake statistic.","Use your own customer evidence or the prospect's own numbers instead.","One honest, sourced figure beats an impressive invented one."],"focus":["precision","impact"]},
    {"id":"precision-sales-early-22","level":"early","profession":"sales","title":"'Should be fine' on the timeline","scenario":"The prospect asks if you can onboard her team before their busy season starts in six weeks. You say 'that should be fine' without checking implementation capacity. That's a promise you can't verify.","task":"Rewrite the answer with the real timeline and the one dependency.","tips":["Give the actual onboarding duration, not a reassurance.","Name what has to be true for the date to hold.","A precise, conditional yes beats a vague, unconditional one."],"focus":["precision","clarity"],"placeholder":"Onboarding runs about two weeks once we have your data export — so yes, comfortably before your busy season if we start by the 15th."},
    {"id":"precision-sales-early-23","level":"early","profession":"sales","title":"The lead-quality claim to marketing","scenario":"You tell the marketing coordinator the webinar leads were 'pretty low quality.' She can't act on that. She needs to know how many, of what kind, and against what bar.","task":"Rewrite the feedback with specific figures and criteria.","tips":["Quantify: X of Y leads had no budget, wrong title, or wrong industry.","Name the bar you're judging against so it's actionable.","'Low quality' is a complaint; the breakdown is a brief."],"focus":["precision","audience"],"placeholder":"Of 40 webinar leads, 12 were students or competitors and 15 had no budget authority — about 13 were genuinely workable."},
    {"id":"precision-sales-early-24","level":"early","profession":"sales","title":"The So-What on account activity","scenario":"You flag to your manager that a target account 'has been really active on our site lately.' She asks what that means for the deal, and you realize you reported the signal without the implication.","task":"Rewrite as What / So What / Now What in three tight sentences.","tips":["What: the specific activity — pages, frequency, who.","So What: what it suggests about their buying stage.","Now What: the action it argues for, now."],"focus":["precision","structure"],"placeholder":"Three people from the account hit our pricing page this week (What); that usually means an active evaluation (So What); I'm reaching out to the economic buyer today (Now What)."},
    {"id":"precision-sales-early-25","level":"early","profession":"sales","title":"The quarter recap that rounds away the truth","scenario":"Your quarter recap to your manager says you 'hit most of your targets and had a solid quarter.' You made 85% of quota, won 6 of 9 forecast deals, and lost your biggest to price. 'Solid' hides all of it.","task":"Rewrite the recap with the real numbers, wins and misses both.","tips":["State attainment as a percentage, not 'most.'","Name the specific miss and its cause — that's the learning.","Honest numbers now earn trust in your future forecasts."],"focus":["precision","impact"],"placeholder":"85% of quota — won 6 of 9 forecast deals; the miss was Hartwell, lost to a 30% undercut on price."}
  ],
  "executive-presence": [
    {"id":"presence-sales-early-01","level":"early","profession":"sales","title":"The menu with no recommendation","scenario":"A prospect asked which plan is right for her 12-person team. Your email lays out all three tiers neutrally and ends 'let me know which you'd like.' She wanted your judgment, not a menu.","task":"Rewrite the close to recommend one tier and say why.","tips":["Own a recommendation — that's what an advisor does.","Tie the pick to her stated needs, not to your margin.","'Whatever you prefer' abdicates the expertise she's paying for."],"focus":["impact","audience"],"placeholder":"For a team your size, I'd go with Plus — you get the reporting your director asked for without paying for seats you won't use."},
    {"id":"presence-sales-early-02","level":"early","profession":"sales","title":"Fact vs. judgment in the deal review","scenario":"In pipeline review you say 'Meridian is a great deal and I feel really good about it.' Your manager can't tell what's fact and what's your optimism. Presence means separating the two clearly.","task":"Rewrite the update splitting the facts from your judgment call.","tips":["State the facts first: stage, commitments, dates.","Then label your read explicitly: 'My call: 80% to close this month.'","Mixing the two makes both look like wishful thinking."],"focus":["impact","structure"],"placeholder":"Facts: proposal sent, VP demo Thursday, verbal interest. My call: 80% to close this month."},
    {"id":"presence-sales-early-03","level":"early","profession":"sales","title":"Signposting the demo","scenario":"You launch into a demo with no map, jumping between features as they occur to you. The prospect can't tell where you are or what's coming, and loses the thread.","task":"Write the 2-3 sentence opening that signposts the demo's structure.","tips":["Tell her the three things you'll show and in what order.","Frame each around her priorities, so she knows why it's there.","A signposted demo feels controlled; a wandering one feels unsure."],"focus":["impact","structure"],"placeholder":"I'll show three things, in the order you raised them: killing manual entry, giving your director visibility, and getting the team live fast."},
    {"id":"presence-sales-early-04","level":"early","profession":"sales","title":"The apology that undercuts you","scenario":"You open your pricing email with 'Sorry to bother you, I know this is probably more than you were hoping to spend...' You've apologized for your own product and pre-conceded the price objection.","task":"Rewrite the opener with presence — no apology, no pre-concession.","tips":["Don't apologize for doing your job or for the price.","State the price plainly and stand behind the value.","Pre-conceding the objection invites it."],"focus":["impact","clarity"],"placeholder":"Here's the pricing for the plan that fits your team, with the ROI math so it's easy to justify internally."},
    {"id":"presence-sales-early-05","level":"early","profession":"sales","title":"Taking a position on the objection","scenario":"A prospect says two competitors are cheaper. You respond 'that's totally fair, they're both good options, it really depends on what you're looking for.' You've talked yourself out of the deal.","task":"Rewrite the response taking a clear, respectful position on why you're the right choice.","tips":["Acknowledge briefly, then make your case with conviction.","'It depends' with no follow-through is surrender.","Presence is holding a view while respecting hers."],"focus":["impact","audience"]},
    {"id":"presence-sales-early-06","level":"early","profession":"sales","title":"The recommendation to your manager","scenario":"You've noticed the team's outreach sequence is underperforming and you have a fix in mind. But your message to your manager just describes the problem and asks 'what do you think we should do?' You had the answer and didn't offer it.","task":"Rewrite the message leading with your recommendation, then the reasoning.","tips":["Bring a recommendation, not just a problem, to your manager.","State what you'd do and why in the first two sentences.","Junior people who recommend get trusted with more."],"focus":["impact","structure"],"placeholder":"I think we should cut the sequence from five touches to three and add a case study at touch two — here's why."},
    {"id":"presence-sales-early-07","level":"early","profession":"sales","title":"Owning the number in the forecast call","scenario":"On the forecast call your manager asks 'are you going to hit your number?' You waffle: 'I hope so, it's kind of close, we'll see.' She needs you to own a call.","task":"Write a 2-sentence answer that owns a clear commit and names the risk.","tips":["Commit to a number and stand behind it.","Name the one thing that could break it — that's ownership, not hedging.","Owning a call, even a cautious one, reads as presence."],"focus":["impact","precision"],"placeholder":"Yes — I'm committing to my number. The one risk is Fairview's legal review; if that slips I'll backfill with Delta."},
    {"id":"presence-sales-early-08","level":"early","profession":"sales","title":"The confident 'here's what I'd do'","scenario":"A customer is unsure whether to add seats now or wait a quarter. She asks your honest advice. Your instinct is to say 'either works, whatever's easier for you' to avoid seeming pushy.","task":"Write the 2-3 sentence answer that gives a genuine recommendation in her interest.","tips":["Give real advice, even if it's 'wait a quarter.'","Advising in her interest builds the trust that closes the next deal.","Neutrality when asked for advice reads as disengagement."],"focus":["impact","audience"]},
    {"id":"presence-sales-early-09","level":"early","profession":"sales","title":"Presence on a stalled deal update","scenario":"A deal has stalled and you're updating your manager. Your draft is defensive and vague: 'they've gone a bit quiet but I'm sure it's fine, just busy on their end probably.' It sounds like you've lost control.","task":"Rewrite the update owning the situation and your plan to unstick it.","tips":["State the stall as a fact, not an excuse.","Show you have a specific plan to re-engage.","Presence is naming a problem and owning the next move."],"focus":["impact","structure"],"placeholder":"Meridian's gone quiet for a week. My read: I lost momentum after the demo. Plan: I'm sending the ROI one-pager today and asking for a decision by Friday."},
    {"id":"presence-sales-early-10","level":"early","profession":"sales","title":"The self-deprecating close","scenario":"You end your demo with 'anyway, that's my little pitch, sorry if I went on too long, no pressure at all.' You've undercut a strong demo with three lines of self-doubt.","task":"Rewrite the close with a confident, clear next step.","tips":["End on the value and the next step, not an apology.","'My little pitch' shrinks what you just did.","Ask for the next step directly — that's what a confident close does."],"focus":["impact","clarity"],"placeholder":"That's how it kills the manual entry your team's drowning in. The natural next step is a pilot — can we start one Monday?"},
    {"id":"presence-sales-early-11","level":"early","profession":"sales","title":"Recommending against the sale","scenario":"A small prospect wants your enterprise tier, but she genuinely only needs the starter plan. The bigger sale helps your quota; the honest recommendation helps her. Presence means giving the honest one.","task":"Write the 2-3 sentence recommendation steering her to the right (smaller) plan.","tips":["Recommend what's right for her, not what's biggest for you.","This is how you earn the referral and the upsell later.","Honest downsell is the strongest presence move there is."],"focus":["impact","audience"],"placeholder":"Honestly, Starter is the right fit for you today — you'd be paying for enterprise features you won't touch. Let's start there and revisit when you scale."},
    {"id":"presence-sales-early-12","level":"early","profession":"sales","title":"The wishy-washy proposal cover note","scenario":"Your proposal cover email reads 'attached is a proposal for your consideration, please review at your convenience and let me know if you have any thoughts.' It has no point of view and no momentum.","task":"Rewrite the cover note with a recommendation and a clear next step.","tips":["Tell her what the proposal recommends and why, in one line.","'At your convenience' invites indefinite delay — propose a time.","A cover note should carry conviction, not just attach a file."],"focus":["impact","clarity"],"placeholder":"The attached proposal recommends the Plus plan for your team — it covers the reporting your director needs. Can we walk through it Thursday?"},
    {"id":"presence-sales-early-13","level":"early","profession":"sales","title":"Fact and opinion in the loss report","scenario":"Reporting a lost deal, you write 'I think they probably chose the competitor mostly because of price, though it might also have been the timing, I'm not totally sure.' Your manager can't separate what you know from what you're guessing.","task":"Rewrite splitting confirmed facts from your inference.","tips":["State what they actually told you as fact.","Label the rest as your inference, clearly.","Clean separation is what makes a loss report useful."],"focus":["impact","precision"],"placeholder":"Fact: they told me price was the deciding factor. My inference: our slow follow-up after the demo didn't help."},
    {"id":"presence-sales-early-14","level":"early","profession":"sales","title":"The junior voice on the group call","scenario":"On a call with the prospect's VP present, you keep prefacing everything with 'this might be a dumb question, but' and 'I'm not the expert, but.' You're signaling low status before you've said anything.","task":"Rewrite two of your lines to state the question or point with quiet confidence.","tips":["Drop the disclaimers — ask the question directly.","'This might be dumb' teaches the room to discount you.","A plain question carries more presence than a hedged one."],"focus":["impact","clarity"]},
    {"id":"presence-sales-early-15","level":"early","profession":"sales","title":"Signposting the pipeline review","scenario":"When it's your turn in pipeline review, you dive straight into deal details with no frame. The room can't tell if you're reporting good news, asking for help, or flagging risk.","task":"Write the 2-sentence opener that signposts what your update covers.","tips":["Tell the room the shape before the detail: 'one close, one risk, one ask.'","Signposting lets people listen for the part that concerns them.","Structure signaled up front reads as control."],"focus":["impact","structure"],"placeholder":"Three things from me: one deal closing this week, one at risk, and one place I need help."},
    {"id":"presence-sales-early-16","level":"early","profession":"sales","title":"The recommendation buried in options","scenario":"A prospect asked whether to run a pilot or go straight to full rollout. You lay out pros and cons of each in careful balance and stop there. She's still stuck because you didn't land the plane.","task":"Rewrite to present the analysis but end with your clear recommendation.","tips":["Balanced analysis is good — but finish with a call.","Say which you'd choose in her position and why.","An analysis without a recommendation offloads the decision back to her."],"focus":["impact","structure"],"placeholder":"Both are viable, but I'd start with a two-week pilot on one team — you prove the value with almost no risk before committing the whole org."},
    {"id":"presence-sales-early-17","level":"early","profession":"sales","title":"Standing behind the price","scenario":"A prospect pushes: 'Can you do better on price?' You immediately fold: 'Let me see what I can do, I'm sure we can figure something out.' You've signaled the price was never real.","task":"Rewrite the response that holds the price with a value-based reason, before any concession.","tips":["Defend the price once before you consider discounting.","Tie the number to the value she'll get.","Instant folding trains her to push on everything."],"focus":["impact","audience"],"placeholder":"The price reflects the full ROI we walked through — it pays back in under five months. Before we talk numbers, is there a specific budget constraint I should know about?"},
    {"id":"presence-sales-early-18","level":"early","profession":"sales","title":"The credit-sharing update","scenario":"You closed a deal partly because a colleague's referral opened the door. Your update to your manager takes full credit. Presence includes giving credit accurately — it makes your wins more, not less, credible.","task":"Rewrite the update stating your win and crediting the assist accurately.","tips":["Own your part clearly; credit the assist honestly.","Managers trust people who report accurately over people who grab.","Accurate credit is a presence signal, not a weakness."],"focus":["impact","clarity"]},
    {"id":"presence-sales-early-19","level":"early","profession":"sales","title":"The confident 'I recommend we pass'","scenario":"A prospect keeps engaging but you've concluded they're a poor fit and unlikely to close. Your manager asks about the deal. Your instinct is to keep it alive in the pipeline to look busy.","task":"Write the 2-3 sentence recommendation to disqualify it, with your reasoning.","tips":["Recommending to drop a bad-fit deal is a presence move, not a failure.","State the evidence: what makes them a poor fit.","A clean pipeline you stand behind beats a padded one."],"focus":["impact","precision"],"placeholder":"I recommend we disqualify Acme — they have no budget this year and no urgency. I'd rather put those hours into Meridian and Delta, which are real."},
    {"id":"presence-sales-early-20","level":"early","profession":"sales","title":"Presence in the campaign debrief","scenario":"You're a marketing coordinator debriefing a campaign that underperformed. Your draft is defensive, listing external reasons it wasn't your fault. Presence means owning the result and the learning.","task":"Rewrite the debrief owning the outcome and the one change you'd make.","tips":["Own the result before explaining context.","Lead with the learning, not the excuse.","Owning a miss cleanly earns you the next budget."],"focus":["impact","structure"],"placeholder":"The campaign missed target — 18 leads against 30. My read: the subject lines were too generic. Next time I'd segment by role and lead with the pain."},
    {"id":"presence-sales-early-21","level":"early","profession":"sales","title":"The neutral demo close that stalls","scenario":"You finish a strong demo and close with 'so, any questions?' The energy deflates and the prospect says she'll 'think about it.' You handed her the exit instead of a next step.","task":"Rewrite the close to recommend the next step and ask for it.","tips":["Don't end on 'any questions' — end on a proposed action.","Recommend the natural next step and ask directly.","Presence is guiding to the next move, not waiting to be led."],"focus":["impact","clarity"],"placeholder":"Based on what you saw, the right next step is a two-week pilot with your ops team. Can we get that started Monday?"},
    {"id":"presence-sales-early-22","level":"early","profession":"sales","title":"Owning a mistake to the customer","scenario":"You quoted a customer the wrong price and now have to correct it. Your draft is a wall of excuses and passive voice: 'an error occurred in the quote that was provided.' Presence is owning it directly.","task":"Rewrite the correction owning the mistake in the first sentence, then the fix.","tips":["Say 'I made an error,' not 'an error occurred.'","Own it fast, then move to the correction and any goodwill gesture.","Clean ownership of a mistake builds more trust than a flawless record."],"focus":["impact","clarity"],"placeholder":"I made a mistake on your quote — I sent $9,000 when the correct figure is $11,500. Here's what happened and how I'll make the transition easy."},
    {"id":"presence-sales-early-23","level":"early","profession":"sales","title":"The recommendation to escalate","scenario":"A deal needs your manager to make an exec-to-exec call to unstick it, but your message just describes the stall and hopes she offers. Presence is recommending the specific action you need from her.","task":"Rewrite the message recommending the exec call and framing it for her.","tips":["Ask for the specific help, don't wait to be offered it.","Frame why the exec call is the right lever now.","Recommending up, with reasoning, reads as ownership."],"focus":["impact","structure"],"placeholder":"I think this needs a call from you to their VP — I've taken it as far as I can at my level. Here's the context and the one ask I'd have you make."},
    {"id":"presence-sales-early-24","level":"early","profession":"sales","title":"Fact vs. spin in the customer QBR","scenario":"You're prepping talking points for a customer check-in. Your draft blurs a real usage problem behind upbeat language: 'engagement is trending in a healthy direction.' Usage is actually down. Presence is stating it and owning the plan.","task":"Rewrite the talking point stating the fact and your plan, no spin.","tips":["State the real number, then your plan to fix it.","Spin gets caught and costs the relationship.","Naming a problem with a plan is stronger than hiding it."],"focus":["impact","precision"],"placeholder":"Straight talk: your team's usage dropped 20% last quarter. Here's what I think is driving it and the two things I'd do about it."},
    {"id":"presence-sales-early-25","level":"early","profession":"sales","title":"The 1:1 ask done with presence","scenario":"In your 1:1 you want your manager to assign you two more strategic accounts, but you soften it into 'if you ever have any accounts that might need someone, I'd be happy to help out I guess.' The ask disappears.","task":"Rewrite the ask directly, with the case for why you've earned it.","tips":["State what you want plainly: two strategic accounts.","Back it with evidence — your recent results.","A clear, earned ask reads as ambition, not entitlement."],"focus":["impact","clarity"],"placeholder":"I'd like to take on two strategic accounts next quarter. I've hit 110% the last two quarters and I'm ready for bigger deals — here's how I'd approach them."}
  ],
  "answering-under-pressure": [
    {"id":"pressure-sales-early-01","level":"early","profession":"sales","title":"The price question you dodge","scenario":"On a discovery call the prospect asks point-blank, 'So how much is this going to cost me?' You feel it's too early and start deflecting into value talk. She notices the dodge and her guard goes up.","task":"Write a 2-3 sentence answer that gives a real range first, then bridges to value.","tips":["Answer the actual question before you steer.","A range with a caveat is honest; a dodge is not.","You can qualify after you answer, not instead of it."],"focus":["clarity","precision"],"placeholder":"For a team your size it's typically $10-14K a year — let me confirm the exact number once I understand your seat count."},
    {"id":"pressure-sales-early-02","level":"early","profession":"sales","title":"'Does it do X?' when it doesn't","scenario":"A prospect asks whether your product does automated approvals. It doesn't — that's on the roadmap. Under pressure you're tempted to say 'sort of' or oversell the workaround.","task":"Write the honest 2-3 sentence answer that says no, then offers the real path.","tips":["Say no clearly — a caught overclaim ends deals.","Offer the workaround or roadmap timing honestly.","An honest no on one feature protects your yes on everything else."],"focus":["clarity","impact"],"placeholder":"Not today — automated approvals ship in Q3. Right now teams handle it with a one-click manual step, and I can show you exactly how."},
    {"id":"pressure-sales-early-03","level":"early","profession":"sales","title":"The question behind the question","scenario":"A prospect asks 'how long have you been in business?' You're a young company and the literal answer (three years) sounds like a weakness. Her real worry is whether you'll still be around to support her.","task":"Write a 2-3 sentence answer that addresses the real concern, honestly.","tips":["Answer the literal question, then address the worry underneath it.","Don't get defensive about being young — reframe with evidence.","Traction and funding speak to survival more than age does."],"focus":["audience","impact"],"placeholder":"Three years, and I know newness raises the 'will they last' question — here's what should reassure you: we're profitable, backed, and [X] customers depend on us daily."},
    {"id":"pressure-sales-early-04","level":"early","profession":"sales","title":"The 'I don't know' you're avoiding","scenario":"A prospect's IT lead asks a technical question about your API rate limits mid-call. You don't know the answer, and you're tempted to guess to look competent. A wrong guess to IT is worse than not knowing.","task":"Write the 2-sentence response that admits you don't know and commits to a real answer.","tips":["'I don't know, let me get you the exact number' beats a confident guess.","Name who you'll ask and by when.","Honesty to a technical buyer builds the credibility bluffing destroys."],"focus":["clarity","precision"],"placeholder":"I don't want to guess on rate limits — let me get the precise figure from our engineering team and send it by end of day."},
    {"id":"pressure-sales-early-05","level":"early","profession":"sales","title":"Pushback on your results claim","scenario":"You cited a customer who cut costs 30%. The prospect challenges: 'That sounds cherry-picked — what about average results?' You feel cornered and want to defend the number.","task":"Write a 2-3 sentence response that answers with specifics, not defensiveness.","tips":["Concede the fair point: that was a strong case, not the average.","Give the honest typical range instead of doubling down.","Answering a challenge with candor wins more trust than the original number did."],"focus":["precision","impact"],"placeholder":"Fair challenge — 30% was one of our best. The typical range is 12-18%, and I'm happy to connect you with a customer closer to your size to hear their real numbers."},
    {"id":"pressure-sales-early-06","level":"early","profession":"sales","title":"The manager's hard question in review","scenario":"In pipeline review your manager asks, 'Why is this deal still open after two months?' You start listing everything you've done. She asked why it's stuck, not what you've done.","task":"Write the 2-3 sentence answer to the question actually asked.","tips":["Answer 'why stuck' directly: the real blocker, in one line.","Your activity log isn't the answer to 'why.'","Then say your plan to unstick it."],"focus":["clarity","structure"],"placeholder":"It's stuck on one thing: their IT team hasn't finished security review. My plan is to get our SE on a call with them this week to close it out."},
    {"id":"pressure-sales-early-07","level":"early","profession":"sales","title":"'Why should I trust a rep?'","scenario":"A blunt prospect says on a cold call: 'No offense, but you're a salesperson — why would I believe anything you tell me?' You feel the jab and want to protest that you're different.","task":"Write a 2-3 sentence reply that disarms the challenge without getting defensive.","tips":["Agree with the healthy skepticism instead of fighting it.","Offer verifiable proof, not more assurances.","Grace under a jab is itself persuasive."],"focus":["audience","impact"],"placeholder":"Totally fair — don't take my word for it. I'll connect you with two customers in your industry, and you can ask them anything you'd ask me."},
    {"id":"pressure-sales-early-08","level":"early","profession":"sales","title":"The competitor comparison you can't fully answer","scenario":"A prospect asks how you compare to a competitor on a specific feature you're not sure about. Under pressure you're tempted to claim you're better anyway.","task":"Write a 2-sentence response that's honest about what you know and don't.","tips":["Say what you're confident about; flag what you'll verify.","Guessing at a competitor's feature is easily disproven.","'Let me confirm rather than guess' reads as trustworthy."],"focus":["precision","clarity"],"placeholder":"On reporting we're clearly stronger; on that specific integration I'd rather confirm the exact detail than guess — I'll have it for you today."},
    {"id":"pressure-sales-early-09","level":"early","profession":"sales","title":"The angry customer on a call","scenario":"A customer calls, upset that a promised feature didn't ship on time. They want to vent and then hear what you'll do. Under pressure you jump straight to excuses about the roadmap.","task":"Write the 2-3 sentence opening that acknowledges first, then answers what they need.","tips":["Acknowledge the frustration before explaining anything.","Answer their real question: what happens now.","Excuses first make the anger worse; ownership first defuses it."],"focus":["audience","impact"],"placeholder":"You're right to be frustrated — we said Q1 and missed it. Here's exactly where it stands and what I'll do to make the wait worth it."},
    {"id":"pressure-sales-early-10","level":"early","profession":"sales","title":"The budget question you weren't ready for","scenario":"A prospect asks 'what kind of budget do most companies your size allocate for this?' It's a fair question and you don't have a clean number ready. You start hedging vaguely.","task":"Write a 2-3 sentence answer that gives a useful real range and a next step.","tips":["Give a genuine range even if approximate.","Anchor it to something concrete: seats, volume, comparable customers.","Then move to sizing hers specifically."],"focus":["precision","clarity"]},
    {"id":"pressure-sales-early-11","level":"early","profession":"sales","title":"'This seems too good to be true'","scenario":"After a strong demo the prospect says, 'Honestly this sounds too good to be true — what's the catch?' Skepticism, not rejection. You want to insist there's no catch, which sounds worse.","task":"Write a 2-3 sentence reply that names a real limitation to earn back credibility.","tips":["Volunteer a genuine constraint — it makes the strengths believable.","'No catch' is what a con artist says.","Honesty about limits is your most persuasive move here."],"focus":["audience","impact"],"placeholder":"Fair to be skeptical. The honest catch: setup takes two weeks of your team's time up front, and it's not the cheapest option — but that's why the results hold."},
    {"id":"pressure-sales-early-12","level":"early","profession":"sales","title":"The interruption that throws you","scenario":"Mid-pitch, the prospect cuts in: 'Just tell me — can you integrate with Salesforce or not?' You were three points from getting there. Under pressure you keep going with your planned pitch.","task":"Write the 2-sentence response that answers her direct question, then resumes.","tips":["Stop and answer the question she interrupted with — immediately.","Yes or no first, one supporting clause, then return.","Barreling past her question signals you're not listening."],"focus":["clarity","audience"],"placeholder":"Yes — native Salesforce integration, two-way sync. That actually ties into the point I was about to make, which is..."},
    {"id":"pressure-sales-early-13","level":"early","profession":"sales","title":"The 'we've been burned before' fear","scenario":"A prospect says a previous vendor overpromised and left them stranded. She's testing whether you'll acknowledge the risk or paper over it. Your instinct is to say 'we're not like them.'","task":"Write a 2-3 sentence reply that takes the fear seriously and offers real protection.","tips":["Validate the fear rather than dismissing it.","Offer a concrete safeguard: pilot, references, exit terms.","'We're different' is what the last vendor said too."],"focus":["audience","impact"],"placeholder":"That's a real risk and I won't pretend it isn't. That's why I'd suggest starting with a paid pilot — you prove it works before you commit, and you can walk if we don't deliver."},
    {"id":"pressure-sales-early-14","level":"early","profession":"sales","title":"Your manager challenges your forecast","scenario":"Your manager pushes back: 'You've had this at 90% for three weeks and it hasn't moved — is it real?' You feel defensive and want to reassert the 90%.","task":"Write a 2-3 sentence answer that engages the challenge honestly.","tips":["Take the challenge as valid data, not an attack.","Re-examine the number out loud: what's actually keeping it at 90.","If it's not really 90, say so — that's the honest move."],"focus":["precision","impact"],"placeholder":"You're right to press — it's been stalled, so 90% is stale. Honestly it's more like 60% until I get a signed order, and here's what I'm doing to force the decision this week."},
    {"id":"pressure-sales-early-15","level":"early","profession":"sales","title":"The security question over your head","scenario":"On a call the prospect's engineer asks about your data residency and encryption key management. You understand roughly half of it. Bluffing risks a follow-up you can't survive.","task":"Write a 2-sentence response that answers what you know and routes the rest correctly.","tips":["Answer the part you're sure of, plainly.","Route the technical depth to your SE rather than faking it.","Knowing your limits reads as competence to an engineer."],"focus":["clarity","audience"],"placeholder":"Data's hosted in-region and encrypted at rest and in transit — that much I can confirm. For key management specifics I want our security lead to answer precisely; I'll set that up this week."},
    {"id":"pressure-sales-early-16","level":"early","profession":"sales","title":"'Send me everything and I'll review'","scenario":"A prospect trying to end the call says 'just send me all the info and I'll get back to you.' It's a soft brush-off. Under pressure you agree and lose the thread.","task":"Write a 2-3 sentence response that answers cooperatively but holds a next step.","tips":["Agree to send materials — but attach a specific follow-up.","Ask one question that keeps the dialogue alive.","'Sure, I'll send it' with no next step is how deals die quietly."],"focus":["audience","impact"],"placeholder":"Happy to — I'll send a focused one-pager, not a data dump. So I send the right thing: is your bigger question about price or about the integration?"},
    {"id":"pressure-sales-early-17","level":"early","profession":"sales","title":"The teammate who calls you out in a meeting","scenario":"In a team meeting a colleague says your lead handoffs have been sloppy and it's costing them time. It stings and it's partly fair. Your instinct is to defend or counterattack.","task":"Write a 2-3 sentence response that engages the criticism without defensiveness.","tips":["Acknowledge the valid part before adding context.","Ask for a specific so you can actually fix it.","Grace under public criticism raises your standing, not lowers it."],"focus":["audience","clarity"]},
    {"id":"pressure-sales-early-18","level":"early","profession":"sales","title":"'Why is your churn so high?'","scenario":"A well-researched prospect asks about a churn figure they found in a review. It's real and it's a soft spot. You want to dispute the number rather than address it.","task":"Write a 2-3 sentence answer that addresses it honestly and gives context.","tips":["Don't dispute a number you can't cleanly refute — contextualize it.","Explain what drove it and what's changed since.","Owning a weak spot credibly beats denying it."],"focus":["precision","impact"]},
    {"id":"pressure-sales-early-19","level":"early","profession":"sales","title":"The demo that breaks live","scenario":"During your demo the product throws an error in front of the prospect. Your instinct is to talk fast and pretend it didn't happen. She saw it.","task":"Write the 2-sentence response that acknowledges it calmly and keeps control.","tips":["Name it plainly — pretending it didn't happen is worse.","Stay calm; your composure is what she's judging now.","Offer to follow up or reroute, then move on without dwelling."],"focus":["impact","clarity"],"placeholder":"That's a demo-environment hiccup, not a product one — let me show you the same flow another way, and I'll send a clean recording after."},
    {"id":"pressure-sales-early-20","level":"early","profession":"sales","title":"'Can you match their price?'","scenario":"A prospect says a competitor came in 25% lower and asks flatly, 'Can you match it?' Under pressure you either fold instantly or refuse defensively.","task":"Write a 2-3 sentence answer that engages the question without an instant yes or no.","tips":["Don't answer the price question before understanding the comparison.","Ask what's included on both sides — often it's not apples to apples.","A calm question beats a reflexive concession or a flat no."],"focus":["audience","impact"],"placeholder":"Let me understand the comparison before I answer on price — is their quote for the same scope and support level? Often the gap isn't what it looks like, and I want to give you a real answer."},
    {"id":"pressure-sales-early-21","level":"early","profession":"sales","title":"The prospect who's clearly stalling","scenario":"A prospect keeps saying 'let me think about it' with no real objection surfacing. You sense there's an unspoken concern. Under pressure you accept the stall and follow up passively.","task":"Write a 2-3 sentence response that surfaces the real objection directly but warmly.","tips":["Name the stall gently and invite the real concern.","'What's the hesitation?' opens more than another follow-up email.","Directness here is a service to both of you."],"focus":["audience","clarity"],"placeholder":"Of course, take the time you need — but I'd rather solve the real concern than have you wonder. What's the one thing that's making you hesitate?"},
    {"id":"pressure-sales-early-22","level":"early","profession":"sales","title":"'I don't have the authority' surprise","scenario":"Late in a deal your champion reveals she can't actually approve the purchase — her director must. You feel the ground shift and want to hide your surprise. The question is how to respond in the moment.","task":"Write a 2-3 sentence response that handles the news gracefully and moves forward.","tips":["Don't show frustration — she's still your ally.","Pivot immediately to how you help her sell it upward.","Turn the setback into a plan for the next call."],"focus":["audience","impact"],"placeholder":"Good to know — that just means we should arm your director with what he needs. Can we set up a short call with him, and can I give you a one-pager to send ahead?"},
    {"id":"pressure-sales-early-23","level":"early","profession":"sales","title":"The manager asks about a deal you neglected","scenario":"Your manager asks about an account you've quietly let go cold. You're tempted to invent recent activity. She'll see through it.","task":"Write a 2-sentence honest answer about the account's real state and your plan.","tips":["Admit you deprioritized it rather than faking activity.","Give the honest reason and your intended next move.","Fabricated activity, once caught, poisons every future update."],"focus":["clarity","precision"],"placeholder":"Honestly I've let that one go cold — I've been heads-down on the two deals closing this month. I'll re-engage it Thursday and know by next week if it's still real."},
    {"id":"pressure-sales-early-24","level":"early","profession":"sales","title":"The hostile question at the webinar","scenario":"You're a marketing coordinator running a live webinar Q&A and an attendee posts a pointed question challenging one of your product claims in front of everyone. You want to skip it.","task":"Write a 2-3 sentence live response that engages it honestly and confidently.","tips":["Don't skip the hard question — the audience noticed it.","Answer directly; concede any fair point.","Handling one tough question well builds trust with everyone watching."],"focus":["audience","impact"]},
    {"id":"pressure-sales-early-25","level":"early","profession":"sales","title":"'What's your best and final?'","scenario":"In a negotiation the buyer says 'give me your best and final number right now.' You feel pressure to blurt a discount. You haven't confirmed the terms that would justify one.","task":"Write a 2-3 sentence response that answers without caving reflexively.","tips":["Don't quote a 'final' number under pressure without your conditions.","Tie any movement to something you get in return (term, volume).","A calm, conditional answer holds more value than a rushed discount."],"focus":["impact","precision"],"placeholder":"I can get you to my best number — but a real 'final' works both ways. If you can commit to the two-year term, here's what I can do; otherwise this is the right price."}
  ],
  "narrative-and-persuasion": [
    {"id":"narrative-sales-early-01","level":"early","profession":"sales","title":"The before-and-after that's missing the before","scenario":"Your pitch jumps straight to how great life is with your product. Without painting the prospect's current pain first, the 'after' has nothing to contrast against and lands flat.","task":"Write a 3-4 sentence pitch that establishes the painful 'before' then the changed 'after.'","tips":["Make the 'before' her current Tuesday — specific and a little uncomfortable.","The gap between before and after is the persuasion.","Skip the before and the after is just a feature list."],"focus":["impact","audience"],"placeholder":"Right now your team spends Friday afternoons reconciling spreadsheets by hand, and errors still slip through. After this, Friday's reconciliation is done by 10am, with a clean audit trail —"},
    {"id":"narrative-sales-early-02","level":"early","profession":"sales","title":"The stakes made abstract","scenario":"Your email says 'inefficiency can hurt your bottom line.' It's true and it's toothless. The prospect feels nothing because the stake is generic.","task":"Rewrite the stakes as a concrete, specific cost in her world.","tips":["Turn 'hurt your bottom line' into a number, a name, or a scene.","Concrete stakes create urgency; abstract ones create nods.","Use her metrics: overtime hours, missed orders, a churned client."],"focus":["impact","precision"],"placeholder":"Last quarter a single mispick cost your team a $40K account — and it wasn't the first."},
    {"id":"narrative-sales-early-03","level":"early","profession":"sales","title":"Pre-empting the price objection","scenario":"You know the prospect's first reaction to your price will be 'that's more than we budgeted.' Your proposal ignores this and hopes it won't come up. It always comes up.","task":"Write 2-3 sentences that raise and answer the price objection before she does.","tips":["Name the objection yourself — it disarms it.","Immediately reframe price against the cost of the status quo.","Pre-empting shows confidence; waiting looks like you hoped she'd miss it."],"focus":["impact","audience"],"placeholder":"I know $12K is above your initial budget. But you're spending closer to $30K a year in lost hours today — so this isn't a new cost, it's a cheaper one."},
    {"id":"narrative-sales-early-04","level":"early","profession":"sales","title":"The customer story with no arc","scenario":"You want to use a customer success story, but your version is a flat list: 'They used our product and got good results.' There's no tension, no turn, nothing memorable.","task":"Rewrite the story with a real arc: their problem, the turning point, the outcome.","tips":["Start with their struggle so there's something to resolve.","Name the moment things changed — the arc needs a turn.","End on a concrete result the prospect can picture for herself."],"focus":["impact","structure"],"placeholder":"Meridian was losing a deal a month to slow quotes. Three weeks after switching, their quote time dropped from two days to two hours — and they closed the next four."},
    {"id":"narrative-sales-early-05","level":"early","profession":"sales","title":"The cost of doing nothing","scenario":"Your prospect is leaning toward 'let's revisit next year.' Your follow-up doesn't make the cost of waiting real, so 'do nothing' feels free and safe to her.","task":"Write 2-3 sentences that make inaction's cost concrete and specific.","tips":["Quantify what another year of the status quo costs her.","Make 'wait' an active choice with a price, not a neutral default.","The strongest competitor is often 'do nothing' — beat it explicitly."],"focus":["impact","precision"],"placeholder":"Waiting a year isn't free — at your current error rate that's roughly $50K in rework and two more quarters of your team's Saturdays."},
    {"id":"narrative-sales-early-06","level":"early","profession":"sales","title":"The campaign story for the sales team","scenario":"You're a marketing coordinator pitching a new campaign idea to skeptical reps. Your draft leads with tactics. The reps won't buy in until they feel the problem the campaign solves for them.","task":"Write a 3-4 sentence pitch that frames the reps' current pain, then the campaign as the fix.","tips":["Open with the reps' frustration: cold lists, no warm intros.","Then show how the campaign changes their day.","Reps buy narratives about their pipeline, not marketing plans."],"focus":["impact","audience"]},
    {"id":"narrative-sales-early-07","level":"early","profession":"sales","title":"Pre-empting 'we don't have time to switch'","scenario":"You know the prospect's real fear is the disruption of switching tools mid-year, though she hasn't said it. Your pitch charges ahead on features, leaving the fear to fester.","task":"Write 2-3 sentences that name the switching fear and defuse it with a concrete plan.","tips":["Say the quiet objection out loud: 'You're probably worried about disruption.'","Follow with the specific, low-effort migration path.","Naming the fear makes you the trustworthy vendor in the room."],"focus":["audience","impact"],"placeholder":"You're probably thinking a switch mid-year is a nightmare. It's not — we migrate your data over a weekend, your team keeps working Monday, and there's a rollback if anything's off."},
    {"id":"narrative-sales-early-08","level":"early","profession":"sales","title":"The event invite with no reason to care","scenario":"Your webinar invite lists the agenda but never says why the prospect's life is worse without attending. It reads like a schedule, not a reason.","task":"Rewrite the invite hook to frame a problem the webinar solves for the attendee.","tips":["Lead with the attendee's problem, then position the event as the answer.","'Learn about X' is weak; 'stop losing Y' is strong.","People attend to fix something, not to be informed."],"focus":["impact","audience"],"placeholder":"If your reps still hand-clean lead lists every morning, you're losing an hour a day per rep. This session shows the three teams that stopped —"},
    {"id":"narrative-sales-early-09","level":"early","profession":"sales","title":"The proposal that lists features, not change","scenario":"Your proposal is a bulleted feature inventory. The prospect can't see the transformation — just a catalog. She needs to picture her team's before and after.","task":"Rewrite the proposal's opening as a change narrative, not a feature list.","tips":["Describe the shift in how her team works, day to day.","Features are evidence for the change, not the story itself.","A proposal that tells a change story gets forwarded and championed."],"focus":["impact","structure"]},
    {"id":"narrative-sales-early-10","level":"early","profession":"sales","title":"Making the ROI human","scenario":"Your ROI slide is all numbers: 'saves 15 hours/week, $30K/year.' The economic case is sound but forgettable. The buyer needs one human image to remember it by.","task":"Write 2-3 sentences that pair the number with a concrete human picture.","tips":["Attach the abstract number to a person's real experience.","'15 hours' is data; 'your team leaves on time Fridays' is memory.","The number persuades the head; the image persuades the gut."],"focus":["impact","audience"],"placeholder":"Fifteen hours a week back means your ops lead stops working Saturdays — that's what the $30K actually buys."},
    {"id":"narrative-sales-early-11","level":"early","profession":"sales","title":"Pre-empting 'my boss won't approve this'","scenario":"Your champion loves the product but you sense she doubts she can sell it upward. If you don't address it, the deal dies silently in her inbox.","task":"Write 2-3 sentences that surface that doubt and equip her to overcome it.","tips":["Name the internal-sell challenge before she stalls on it.","Hand her the exact argument her boss will respond to.","You're not just selling her — you're arming her to sell for you."],"focus":["audience","impact"],"placeholder":"The last hurdle is usually your director. Here's the one-line case that lands with finance folks: it pays back in under five months and de-risks your busy season. Want me to draft the note you'd send him?"},
    {"id":"narrative-sales-early-12","level":"early","profession":"sales","title":"The demo with no story spine","scenario":"Your demo is a click-tour of features in whatever order they appear on screen. There's no narrative connecting them, so the prospect remembers nothing an hour later.","task":"Write a 2-3 sentence framing that gives the demo a story spine: a day in her team's life.","tips":["Frame the demo as walking through her team's actual workflow.","Each feature enters where it solves that day's problem.","A story-shaped demo is remembered; a feature tour is forgotten."],"focus":["impact","structure"],"placeholder":"Let's walk through a normal Monday for your team — an order comes in, and I'll show you where each headache disappears, step by step."},
    {"id":"narrative-sales-early-13","level":"early","profession":"sales","title":"The urgency that isn't manufactured","scenario":"You want to create urgency but your only tool has been a fake 'this offer expires Friday.' The prospect sees through it. Real urgency comes from her situation, not your calendar.","task":"Write 2-3 sentences that build genuine urgency from her own timeline.","tips":["Anchor urgency to her deadline, not an invented one.","Her busy season, her budget cycle, her competitor — those are real.","Manufactured deadlines erode trust; real ones focus decisions."],"focus":["impact","audience"],"placeholder":"Your busy season starts in six weeks, and onboarding takes two. If we don't start by the 15th, you'll be fighting the surge with the old process again."},
    {"id":"narrative-sales-early-14","level":"early","profession":"sales","title":"The testimonial you're wasting","scenario":"You have a glowing quote from a happy customer but you drop it at the bottom of the email with no setup. Unframed, it's just praise the prospect scrolls past.","task":"Rewrite so the testimonial answers the prospect's specific doubt.","tips":["Place the quote right where it rebuts her concern.","Frame it: 'You worried about X — here's a customer who did too.'","A testimonial aimed at a doubt persuades; a floating one decorates."],"focus":["impact","audience"]},
    {"id":"narrative-sales-early-15","level":"early","profession":"sales","title":"The renewal story that assumes gratitude","scenario":"Your renewal pitch assumes the customer remembers all the value you delivered. She doesn't — she remembers the invoice. You need to retell the year as a story of what changed for her.","task":"Write a 3-4 sentence renewal narrative: where she started, what changed, what's at stake if she stops.","tips":["Remind her of the 'before' she's forgotten.","Show the distance traveled with her own numbers.","Frame renewal as protecting the gain, not repeating a purchase."],"focus":["impact","precision"],"placeholder":"A year ago your team was drowning in manual orders and errors ran at 3%. Today it's automated and errors are under 1%. Renewing keeps that; dropping it means going back to the spreadsheets."},
    {"id":"narrative-sales-early-16","level":"early","profession":"sales","title":"Pre-empting 'we can build this ourselves'","scenario":"A technical prospect hints they could build a version internally. If you ignore it, they'll use it as a reason to pass. You need to address the build-vs-buy question head on.","task":"Write 2-3 sentences that acknowledge the build option and reframe the real cost.","tips":["Concede they could build it — don't insult their team.","Reframe on hidden costs: maintenance, opportunity cost, time-to-value.","Respecting the objection makes your rebuttal land."],"focus":["audience","impact"],"placeholder":"Your team absolutely could build this. The question is whether you want two engineers maintaining it for the next three years instead of shipping your own product — that's the real cost of build."},
    {"id":"narrative-sales-early-17","level":"early","profession":"sales","title":"The cold email that tells no story","scenario":"Your cold email states what you do and asks for a meeting. There's no narrative hook — nothing that makes the reader see herself in it. It reads like every other pitch in her inbox.","task":"Rewrite the opening as a one-line story the prospect recognizes as her own.","tips":["Open with a scene from her world, not a description of yours.","If she thinks 'that's exactly us,' you've earned the read.","A recognizable story beats a clear pitch for openings."],"focus":["impact","audience"],"placeholder":"Every month-end, someone on your finance team stays late chasing invoice mismatches. We made that night disappear for three teams like yours —"},
    {"id":"narrative-sales-early-18","level":"early","profession":"sales","title":"Framing the pilot as the safe choice","scenario":"The prospect is nervous about committing. You want to propose a pilot, but framing it as 'just a small trial' makes it sound tentative. Frame it as the smart, low-risk path to a decision.","task":"Write 2-3 sentences that frame the pilot as the confident, de-risked way forward.","tips":["Position the pilot as proof-before-commitment, not hesitation.","Make the 'before' the risk of a blind full purchase.","The pilot is the answer to her fear — sell it that way."],"focus":["impact","audience"],"placeholder":"You shouldn't take my word that this works — you should see it on your own data. A two-week pilot proves it with one team, zero risk, before you commit a dollar to the rollout."},
    {"id":"narrative-sales-early-19","level":"early","profession":"sales","title":"The competitive displacement story","scenario":"You're trying to win a prospect away from an incumbent. Your pitch attacks the competitor, which makes the prospect defensive about her past choice. You need a story that lets her switch without admitting a mistake.","task":"Write 2-3 sentences that frame switching as her outgrowing the old tool, not having chosen wrong.","tips":["Don't make her past decision look foolish — validate it.","Frame the switch as her needs evolving, not the tool failing.","People switch to protect their pride as much as their process."],"focus":["audience","impact"],"placeholder":"CompetitorX was the right call when you had five people. But you've grown into a different problem now — and that's exactly the point where teams your size move to us."},
    {"id":"narrative-sales-early-20","level":"early","profession":"sales","title":"Making a dry stat land","scenario":"Your strongest data point — '99.9% uptime' — is technically impressive but emotionally inert. The prospect nods and forgets it. You need to translate it into a stake she feels.","task":"Rewrite the stat so its meaning for her is concrete and memorable.","tips":["Translate the number into what its absence would cost her.","'99.9% uptime' becomes 'your team never loses a morning to an outage.'","Give the abstract figure a consequence she can picture."],"focus":["impact","precision"],"placeholder":"99.9% uptime means, in plain terms, your team has never once had to tell a customer 'the system's down' — that's what it's worth."},
    {"id":"narrative-sales-early-21","level":"early","profession":"sales","title":"The event follow-up with a shared moment","scenario":"You met a prospect at a conference and had a real conversation about her scaling pains. Your follow-up email is generic and forgets the moment you shared. You've thrown away your best hook.","task":"Write a 2-3 sentence follow-up that reopens with the specific moment and turns it into the case.","tips":["Anchor the email in the exact thing she said, in her words.","Bridge from that moment to how you solve it.","The shared moment is warmth no template can fake."],"focus":["audience","impact"],"placeholder":"You mentioned your team doubled but your order process didn't — and that Fridays have become a scramble. That's the exact problem we fixed for [customer]; here's how."},
    {"id":"narrative-sales-early-22","level":"early","profession":"sales","title":"Pre-empting the 'too small a vendor' worry","scenario":"You're a small company selling to a larger enterprise. The unspoken worry is that you're too small to be reliable. If you don't address it, procurement will quietly rule you out.","task":"Write 2-3 sentences that raise the size concern and reframe it as an advantage.","tips":["Name the concern before they use it against you.","Reframe small as attentive, fast, and invested in their success.","Turn the perceived weakness into your differentiator."],"focus":["audience","impact"],"placeholder":"You might wonder if a company our size can support an org yours. Here's the flip side: you get our team on a first-name basis and features you request in weeks, not a ticket in a queue behind ten thousand others."},
    {"id":"narrative-sales-early-23","level":"early","profession":"sales","title":"The internal pitch for a bigger territory","scenario":"You want your manager to expand your territory. Your draft just asks for it. You need a narrative: what you've proven, what's now possible, what's lost if the status quo holds.","task":"Write a 3-4 sentence persuasive case with a clear before, after, and stake.","tips":["Before: what you've done with your current patch.","After: what a bigger territory unlocks, with a number.","Stake: the opportunity being left on the table right now."],"focus":["impact","structure"],"placeholder":"I've hit 115% two quarters running on a mid-market patch. Give me the enterprise segment and I think I can add $200K in pipeline next quarter — right now those accounts are getting no coverage at all."},
    {"id":"narrative-sales-early-24","level":"early","profession":"sales","title":"The demo recap that doesn't sell the next step","scenario":"Your post-demo recap summarizes what you showed but doesn't build a case for the pilot you want. It informs without persuading, and the deal drifts.","task":"Rewrite the recap to frame the pilot as the natural next chapter of the story.","tips":["Connect what she saw to the specific problem it solves for her.","Make the pilot the obvious continuation, not a new ask.","End the recap where the story wants to go next."],"focus":["impact","structure"]},
    {"id":"narrative-sales-early-25","level":"early","profession":"sales","title":"The objection you should raise yourself","scenario":"Your product genuinely isn't the cheapest, and the prospect is price-sensitive. Hiding this until she finds it makes you look evasive. Raising it yourself, framed right, builds trust.","task":"Write 2-3 sentences that volunteer the price truth and reframe it as a deliberate choice.","tips":["Say it plainly: you're not the cheapest, and why.","Reframe the higher price as what the reliability she needs costs.","Volunteering your weakness is the most persuasive honesty there is."],"focus":["impact","audience"],"placeholder":"I'll be straight: we're not the cheapest option on your list. We're priced for teams that can't afford a failed rollout — and given your busy season, I think that's you."}
  ],
  "delivering-hard-messages": [
    {"id":"hard-sales-early-01","level":"early","profession":"sales","title":"Telling a prospect you can't do the feature","scenario":"A prospect's decision hinges on a feature you don't have and won't build. Your draft dances around it with 'we're always evolving our roadmap.' She deserves a straight answer so she can decide.","task":"Write a 2-3 sentence message that gives the clear no up front, then what you can offer.","tips":["Front-load the no — the vague version wastes her time.","'Clear is kind' — a straight no lets her plan.","Follow the no with the honest alternative or workaround."],"focus":["clarity","impact"],"placeholder":"I want to be straight with you: we're not building automated approvals, and I don't want you to buy hoping we will. Here's the manual workaround and whether it's enough for your case."},
    {"id":"hard-sales-early-02","level":"early","profession":"sales","title":"The price went up at renewal","scenario":"You have to tell a loyal customer her renewal price is increasing 8%. Your draft buries it in paragraph four behind a wall of appreciation. She'll feel ambushed when she finds it.","task":"Write a 2-3 sentence message that states the increase early and plainly, then the reason.","tips":["Lead with the number and the effective date — don't bury it.","Burying bad news reads as a trap when found.","One honest sentence of reason beats a page of cushioning."],"focus":["clarity","impact"],"placeholder":"I want to give you a heads-up before renewal: your price is going up 8%, to $12,960, starting next term. Here's why, and one option to soften it."},
    {"id":"hard-sales-early-03","level":"early","profession":"sales","title":"Declining the discount request","scenario":"A prospect asked for a 30% discount and you can't go near it. Your draft is apologetic and wishy-washy, leaving her thinking there's room. You need a clean, respectful no.","task":"Write a 2-3 sentence response that says no clearly and holds the value.","tips":["Give a clean no, not a maybe that invites more pushing.","Explain the value the price reflects, briefly.","A firm, kind no respects both of you more than false hope."],"focus":["clarity","impact"],"placeholder":"I can't do 30% — that's not a negotiating line, it's genuinely below what makes this work. What I can do is show you why the price pays for itself, and offer a small annual-commit discount."},
    {"id":"hard-sales-early-04","level":"early","profession":"sales","title":"Behavior-impact-ask to a colleague","scenario":"A colleague keeps sending you unqualified leads that waste your time, and it's straining the working relationship. You need to raise it without an accusation. Use behavior, impact, then a specific ask.","task":"Write a 3-sentence message: the specific behavior, its impact on you, and a clear ask.","tips":["Describe the behavior factually, not as a character flaw.","State the concrete impact on your work.","End with a specific, doable ask — not a vague grievance."],"focus":["clarity","structure"],"placeholder":"The last few handoffs came without budget or timeline confirmed (behavior), so I've spent hours on calls that disqualify in five minutes (impact). Could we agree on a two-line qualification check before handoff? (ask)"},
    {"id":"hard-sales-early-05","level":"early","profession":"sales","title":"Telling your manager you'll miss quota","scenario":"It's clear you'll finish the month at 70% of quota. Your instinct is to wait and hope, or to soften it heavily. Your manager needs the clear message now so she can adjust.","task":"Write a 2-3 sentence message that states the miss plainly and your read on why.","tips":["Front-load the number — she needs it to plan, not to be spared.","Give the honest cause, not a list of excuses.","Delivering a miss early and clearly protects your credibility."],"focus":["clarity","precision"],"placeholder":"I'm going to land around 70% this month. Two deals slipped to next month on legal review — real, not lost. Here's my plan to pull one back and how next month looks."},
    {"id":"hard-sales-early-06","level":"early","profession":"sales","title":"The missed commitment to a customer","scenario":"You promised a customer a report by Friday and it won't be ready. Your draft over-apologizes and offers three excuses. She needs the news, a new date, and less drama.","task":"Write a 2-3 sentence message: the miss, the new date, one line of ownership.","tips":["State the slip and the firm new date up front.","One clean 'this is on me' beats three excuses.","Give her a date she can rely on this time."],"focus":["clarity","impact"],"placeholder":"The report won't be ready Friday — that's on me for underestimating the data pull. You'll have it Tuesday by noon, and I'll send a preview Monday so you're not waiting blind."},
    {"id":"hard-sales-early-07","level":"early","profession":"sales","title":"Disqualifying a prospect who wants to buy","scenario":"A prospect is eager but genuinely a bad fit — your product won't solve her problem. It's tempting to take the sale. The kind and right thing is to tell her.","task":"Write a 2-3 sentence message that honestly tells her it's not the right fit.","tips":["Say plainly it's not the right fit and why.","Point her toward what would actually help, if you can.","An honest disqualification earns a referral you'd never get otherwise."],"focus":["clarity","impact"],"placeholder":"I have to be honest — we're not the right tool for what you described. You need real-time inventory sync and we run hourly, which would frustrate you. Here's who I'd actually look at for that."},
    {"id":"hard-sales-early-08","level":"early","profession":"sales","title":"Pushing back on your manager's ask","scenario":"Your manager wants you to hit an outreach quota you think is counterproductive — it'll burn good accounts. You need to disagree respectfully and clearly, not just comply or grumble.","task":"Write a 2-3 sentence message that states your disagreement and the alternative.","tips":["State the concern directly, grounded in evidence.","Offer an alternative, not just an objection.","Respectful, clear pushback is more useful to her than silent compliance."],"focus":["clarity","impact"]},
    {"id":"hard-sales-early-09","level":"early","profession":"sales","title":"The 'we chose someone else' you must deliver","scenario":"You're now on the buying side of a small vendor decision, and you have to tell a vendor rep who worked hard that you picked a competitor. Ghosting is easier; a clean message is kinder.","task":"Write a 2-3 sentence message that delivers the no clearly and respectfully.","tips":["Give the clear no — don't leave them chasing.","One honest reason helps them more than silence.","Treating a losing vendor well is how you'd want to be treated."],"focus":["clarity","impact"]},
    {"id":"hard-sales-early-10","level":"early","profession":"sales","title":"Correcting a teammate's public error","scenario":"In a shared channel, a teammate posted wrong pricing that a prospect might see. You need to correct it fast without embarrassing them. Clear on the facts, gentle on the person.","task":"Write a 2-sentence correction that fixes the facts without a jab.","tips":["Correct the fact plainly and immediately.","Keep the person out of it — no blame, just the fix.","Speed and kindness together; the error, not the teammate, is the target."],"focus":["clarity","impact"],"placeholder":"Quick correction so nobody quotes the wrong number: the 20-seat plan is $12K, not $9K. Thanks — easy mix-up with the old sheet."},
    {"id":"hard-sales-early-11","level":"early","profession":"sales","title":"Telling CS about the promise you made","scenario":"You closed a deal by promising the customer a custom onboarding that CS didn't agree to and may not be able to deliver. You need to tell CS the hard truth before the customer does.","task":"Write a 2-3 sentence message owning the promise and asking for help delivering it.","tips":["Own it clearly — don't let CS discover it from the customer.","State exactly what you promised and by when.","Ask for help, don't dump the problem — you made it."],"focus":["clarity","structure"],"placeholder":"I need to flag something I promised to close Delta: a custom onboarding session in week one. That's on me to have offered without checking — can we figure out together how to deliver it?"},
    {"id":"hard-sales-early-12","level":"early","profession":"sales","title":"The renewal you have to warn is at risk","scenario":"You have to tell your manager a big renewal is likely to churn. Your instinct is to keep hoping and not spook her. She needs the honest early warning to help.","task":"Write a 2-3 sentence message that states the churn risk plainly and what you need.","tips":["Front-load the risk — early warning is the whole value.","Give the specific reasons, not a vague worry.","Say what help would change the odds."],"focus":["clarity","precision"],"placeholder":"Heads-up: Acme's renewal is genuinely at risk — usage is down 40% and their champion left. I think we can save it, but I'll need you on an exec call. Can we talk today?"},
    {"id":"hard-sales-early-13","level":"early","profession":"sales","title":"Feedback to marketing on lead quality","scenario":"The leads from marketing's last campaign were poor and it's affecting your numbers. You've been silently frustrated. You need to give clear, useful feedback without torching the relationship.","task":"Write a 3-sentence message using behavior, impact, ask — specific and non-accusatory.","tips":["Describe what the leads were, factually, with numbers.","State the impact on your pipeline honestly.","Ask for a specific change, framed as partnership."],"focus":["clarity","audience"],"placeholder":"Of last month's 40 leads, about 15 had no budget authority (behavior), so my conversion dropped and I lost time (impact). Could we add a budget-qualifier question to the webinar signup? (ask)"},
    {"id":"hard-sales-early-14","level":"early","profession":"sales","title":"Saying no to a prospect's timeline","scenario":"A prospect wants to be fully live in two weeks and that's not realistic — it needs four. Promising two weeks to keep her happy sets up a worse conversation later. Tell her now.","task":"Write a 2-3 sentence message that says the timeline won't work and gives the real one.","tips":["Give the honest timeline, not the one she wants to hear.","A realistic date now beats a broken promise later.","Show the plan that makes the real date credible."],"focus":["clarity","precision"],"placeholder":"I can't promise two weeks and mean it — a real go-live is four, and I'd rather tell you that now than miss it. Here's the week-by-week so you can see why, and how we protect your busy-season date."},
    {"id":"hard-sales-early-15","level":"early","profession":"sales","title":"Admitting the demo oversold","scenario":"You realize a capability you demoed doesn't work quite the way you implied, and the prospect is about to sign based on it. Coming clean now is hard; letting her sign on a misunderstanding is worse.","task":"Write a 2-3 sentence message that corrects the record before she signs.","tips":["Own the overstatement plainly before the contract.","State what the feature actually does.","Correcting yourself pre-signature builds trust; getting caught post-signature destroys it."],"focus":["clarity","impact"],"placeholder":"Before you sign, I need to correct something from the demo — I made the approval flow sound fully automated, and it's actually one manual click. I'd rather you know now than feel misled later."},
    {"id":"hard-sales-early-16","level":"early","profession":"sales","title":"The hard update in pipeline review","scenario":"Your biggest deal, which the whole team is counting on, just died. You have to announce it in pipeline review. The urge is to soften and cushion; the room needs the clear news.","task":"Write the 2-3 sentence spoken update that states the loss cleanly, then the plan.","tips":["State the loss in the first sentence — no long wind-up.","Give the reason briefly and honestly.","Move to the plan so it's news plus a path, not just bad news."],"focus":["clarity","impact"],"placeholder":"Hard news: we lost Hartwell — they went with CompetitorX on price, 30% under us. Here's what I learned and the two deals I'm accelerating to cover the gap."},
    {"id":"hard-sales-early-17","level":"early","profession":"sales","title":"Declining to bend a policy","scenario":"A friendly customer asks you to bend the contract terms in a way you can't. Because you like her, you're tempted to imply it might be possible. A clear no now is kinder than false hope.","task":"Write a 2-3 sentence response that declines clearly while preserving the relationship.","tips":["Say no to the request without saying no to her.","Don't leave a door open you can't actually walk through.","Explain the constraint honestly, then offer what you can do."],"focus":["clarity","audience"]},
    {"id":"hard-sales-early-18","level":"early","profession":"sales","title":"Raising an ethics concern to your manager","scenario":"Your manager suggested implying a feature is 'coming soon' when there's no real plan to build it. You're uncomfortable. You need to push back clearly without accusing her of anything.","task":"Write a 2-3 sentence message that raises the concern and proposes an honest alternative.","tips":["Name the concern calmly, focused on the risk not the accusation.","Propose the honest version that still moves the deal.","Clear on the issue, generous on intent."],"focus":["clarity","impact"]},
    {"id":"hard-sales-early-19","level":"early","profession":"sales","title":"Telling the customer about the outage","scenario":"A service outage affected your customer's operations this morning. Your draft opens with technical detail and reassurance, burying the acknowledgment. She wants ownership first.","task":"Write a 2-3 sentence message that owns the outage first, then the facts and fix.","tips":["Acknowledge the impact on her before explaining the cause.","Front-load the ownership; details come second.","She needs to feel heard before she can hear your explanation."],"focus":["clarity","impact"],"placeholder":"Your team lost about two hours this morning to our outage, and that's on us. Here's exactly what happened, what's fixed, and what we're doing so it doesn't recur."},
    {"id":"hard-sales-early-20","level":"early","profession":"sales","title":"The 'stop contacting our team' request","scenario":"A prospect's team member complained that your outreach cadence is too aggressive. You need to reply, own it, and reset — not get defensive about doing your job.","task":"Write a 2-3 sentence reply that owns the over-contact and resets respectfully.","tips":["Acknowledge the complaint without defensiveness.","Take clear action: reduce cadence, single point of contact.","Owning it well can salvage a relationship you were about to lose."],"focus":["clarity","audience"]},
    {"id":"hard-sales-early-21","level":"early","profession":"sales","title":"Correcting your manager's wrong assumption","scenario":"In a forecast meeting your manager states a deal is 'basically closed' when it's actually shaky. Letting it stand risks a worse surprise later. You need to correct her, in the room, clearly and respectfully.","task":"Write the 2-3 sentence spoken correction that sets the record straight without undermining her.","tips":["Correct the fact, not the person — keep it about the deal.","Give the real status and the one open risk.","A respectful correction now prevents a public miss later."],"focus":["clarity","impact"],"placeholder":"Want to flag one thing on Meridian — it's further along than most, but not closed. There's still budget sign-off outstanding, so I'd forecast it at 70, not committed, until I have the PO."},
    {"id":"hard-sales-early-22","level":"early","profession":"sales","title":"The feature request you must decline internally","scenario":"You promised a prospect you'd 'fight for' a feature, but after checking, product won't build it and you were wrong to imply you had that power. You have to go back to the prospect with the no.","task":"Write a 2-3 sentence message that corrects your overreach and delivers the honest no.","tips":["Own that you overstated your influence.","Deliver the clear no on the feature.","Offer the real alternative so the deal isn't dead."],"focus":["clarity","impact"]},
    {"id":"hard-sales-early-23","level":"early","profession":"sales","title":"Ending the pursuit of a stalled deal","scenario":"You've decided to stop chasing a prospect who keeps going quiet. Rather than fade away, a clean 'closing the loop' message is more professional and sometimes revives the deal.","task":"Write a 2-3 sentence message that respectfully closes the loop and leaves a door open.","tips":["State plainly that you'll stop reaching out for now.","No guilt-trip — keep it gracious.","A clean close sometimes gets the reply that six follow-ups didn't."],"focus":["clarity","audience"],"placeholder":"I don't want to keep landing in your inbox, so I'll close the loop here. If the timing changes and reconciling those invoices is still a headache, I'm one reply away. Wishing you a smooth quarter."},
    {"id":"hard-sales-early-24","level":"early","profession":"sales","title":"Telling a customer their use case won't work","scenario":"An existing customer wants to use your product for something it wasn't built for and will fail at. It's tempting to let them try to keep them happy. The kind move is to tell them plainly.","task":"Write a 2-3 sentence message that warns them clearly and redirects.","tips":["Say clearly that the use case won't work and why.","Better to disappoint now than after they've built on it.","Redirect to what the product does do well, or a better tool."],"focus":["clarity","impact"]},
    {"id":"hard-sales-early-25","level":"early","profession":"sales","title":"Admitting you dropped the ball to a customer","scenario":"You forgot to follow up on a customer's request for two weeks and she's rightly annoyed. Your draft is a paragraph of excuses. She needs a clean apology and a fix, not a defense.","task":"Write a 2-3 sentence message that owns the lapse plainly and states the fix.","tips":["Own it in the first sentence — no excuse cushion.","One 'this is on me' outperforms three explanations.","Move fast to the concrete fix and timeline."],"focus":["clarity","impact"],"placeholder":"You're right, and I owe you an apology — I dropped your request for two weeks with no good excuse. Here's what I'm doing today to make it right, and how I'll make sure it doesn't happen again."}
  ],
  "putting-it-together": [
    {"id":"together-sales-early-01","level":"early","profession":"sales","title":"The whole cold email, done right","scenario":"You're writing one cold email to an operations manager, from scratch. It has to lead with her problem, speak her language, stay short, make one clear ask, and sound human — everything at once.","task":"Write a complete cold email under 90 words: hook, one proof point, one ask.","tips":["Lead with her problem, not your company.","One proof point, one ask, zero filler.","Read it as her: would you reply?"],"focus":["impact","concision"]},
    {"id":"together-sales-early-02","level":"early","profession":"sales","title":"The discovery recap that does everything","scenario":"After a strong discovery call you owe the prospect a recap. It must lead with the next step, be structured, precise on what was agreed, and end with one clear question — all in a scannable email.","task":"Write the full recap email: BLUF next step, a short structured body, one clear question.","tips":["Open with the confirmed next step and date.","Group the substance into two or three labeled lines.","Close with a single question, not three."],"focus":["structure","clarity"],"placeholder":"Confirming our demo Thursday at 2pm with you and your VP. Quick recap of what we covered, and one question below —"},
    {"id":"together-sales-early-03","level":"early","profession":"sales","title":"Register: same news, three channels","scenario":"Meridian just signed. You need to tell your manager (Slack), the customer success team (handoff email), and celebrate on the team channel. Same fact, three registers.","task":"Write the three versions — each 1-2 sentences, matched to its channel and reader.","tips":["Slack to manager: the number and what's next.","CS email: what they bought and what you promised.","Team channel: brief, warm, credit where due."],"focus":["audience","concision"]},
    {"id":"together-sales-early-04","level":"early","profession":"sales","title":"The objection reply, fully assembled","scenario":"A prospect emailed a real objection: your product is pricier than the incumbent and switching feels risky. You need to answer the actual concern, pre-empt the follow-up, and stay concise and confident.","task":"Write the complete reply: acknowledge, reframe with evidence, one clear next step.","tips":["Answer the real fear (risk of switching), not just price.","One proof point and one de-risking offer.","End with a concrete next step, not 'let me know.'"],"focus":["impact","audience"]},
    {"id":"together-sales-early-05","level":"early","profession":"sales","title":"The pipeline review, start to finish","scenario":"It's your turn in pipeline review. You have three minutes to cover a close, a risk, and an ask — signposted, precise on numbers, owning your calls, and ending with what you need.","task":"Write your full 4-6 sentence spoken update: signpost, three items, clear ask.","tips":["Signpost the shape in one line first.","One deal each: close, risk, ask — with numbers and dates.","End on the specific help you need."],"focus":["structure","impact"],"placeholder":"Three things: one closing, one at risk, one ask. Closing: Meridian, $9K, signature expected Friday..."},
    {"id":"together-sales-early-06","level":"early","profession":"sales","title":"The proposal cover email that carries it all","scenario":"You're sending a proposal. The cover email must state your recommendation, frame the value narrative briefly, pre-empt the price reaction, and propose a specific next step — without becoming a wall of text.","task":"Write the full cover email in under 120 words with all four elements.","tips":["Lead with the recommendation, not 'attached please find.'","One line of before/after value; one line pre-empting price.","Propose a specific time to walk through it."],"focus":["impact","structure"]},
    {"id":"together-sales-early-07","level":"early","profession":"sales","title":"The event follow-up sequence opener","scenario":"You met 12 warm prospects at a conference and need a follow-up email you'll personalize for each. It must reopen with a shared moment, connect to their problem, and ask for a call — a reusable but human template.","task":"Write the template with a clearly marked personalization slot, under 80 words.","tips":["Leave an obvious slot for the specific moment you shared.","Bridge from their stated pain to your solution in one line.","One ask: a specific call window."],"focus":["audience","concision"],"placeholder":"Great talking at [event] about [their specific pain] —"},
    {"id":"together-sales-early-08","level":"early","profession":"sales","title":"The at-risk-renewal message to your manager","scenario":"A major renewal is wobbling. You must tell your manager the hard news clearly, give precise evidence, own your read, and ask for the specific help you need — all in a message she can act on in ten seconds.","task":"Write the full message: BLUF the risk, evidence, your plan, your ask.","tips":["Front-load the risk and its size.","Two precise facts, not a vague worry.","End with the one thing you need from her, by when."],"focus":["clarity","precision"],"placeholder":"Flagging a real churn risk on Acme, our second-biggest renewal. Usage down 40%, champion just left. My plan and the one ask I have below —"},
    {"id":"together-sales-early-09","level":"early","profession":"sales","title":"The demo, framed and closed","scenario":"You're running a demo end to end. It needs a signposted opening built on her three priorities, a story spine through her workflow, and a confident close that recommends the next step — not 'any questions?'","task":"Write the demo's opening frame (2-3 sentences) and its closing ask (2 sentences).","tips":["Open by naming the three things you'll show, in her priority order.","Close on a recommended next step and ask for it directly.","Bookend the demo so it feels controlled and lands somewhere."],"focus":["structure","impact"]},
    {"id":"together-sales-early-10","level":"early","profession":"sales","title":"The CS handoff that leaves nothing out","scenario":"You're handing a closed deal to customer success. The doc must be structured for CS's needs, precise on promises made, flag the one landmine up front, and stay scannable — a real working document.","task":"Write the handoff's opening: BLUF the one thing CS must know, then 3 labeled sections.","tips":["Lead with the landmine — the promise or gap that could blow up.","Section it: account goal, what they bought, promises and dates.","Write for CS's job, not your deal diary."],"focus":["structure","audience"],"placeholder":"One thing to manage from day one: I promised a custom onboarding session in week one. Full handoff below —"},
    {"id":"together-sales-early-11","level":"early","profession":"sales","title":"The weekly manager update, polished","scenario":"Your Friday update to your manager should use your fixed buckets, precise numbers, owned calls, and flag anything you need — readable in fifteen seconds and requiring no follow-up questions.","task":"Write the full update: Closed / Moving / Stuck, one to two lines each with numbers and asks.","tips":["Fixed buckets so she knows where to look.","Numbers and dates, not adjectives.","Every 'Stuck' item carries a specific ask."],"focus":["structure","concision"],"placeholder":"Closed: Meridian $9K. Moving: Delta ($15K) and Fairview ($8K) on track. Stuck: Northgate — need legal by Wed."},
    {"id":"together-sales-early-12","level":"early","profession":"sales","title":"The price-increase message, fully handled","scenario":"You must tell a loyal customer her renewal price is rising 8%. The message needs the news up front, her results as context, a plain reason, and one option to soften it — clear, kind, and confident.","task":"Write the complete message with all four elements, under 120 words.","tips":["State the number and date early — no burying.","Anchor it in the value she got this year.","Offer one concrete lever (annual lock, added seats)."],"focus":["clarity","impact"]},
    {"id":"together-sales-early-13","level":"early","profession":"sales","title":"The champion enablement kit","scenario":"Your champion has to sell the purchase to her COO. You'll give her a short, pasteable summary written in her voice for his priorities: cost, risk, payoff — one number, one risk addressed, one recommendation.","task":"Write the 3-4 sentence summary she can forward to her COO unedited.","tips":["Write for the COO's priorities, in her voice.","One number, one risk handled, one clear recommendation.","If she has to rewrite it, you've failed her."],"focus":["audience","concision"]},
    {"id":"together-sales-early-14","level":"early","profession":"sales","title":"The campaign recap for two readers","scenario":"You're a marketing coordinator recapping a campaign. The sales director wants pipeline impact; your marketing manager wants the metrics. Write one recap that leads for the primary reader and sections the rest.","task":"Write the recap: headline result, a sales-impact line, then a labeled metrics block.","tips":["Pick the primary reader and lead for them.","Headline the number that matters most to that reader.","Put the secondary detail in a clearly labeled section below."],"focus":["audience","structure"],"placeholder":"Headline: the Q2 campaign put 42 qualified leads into the pipeline, double target — sales impact and full metrics below."},
    {"id":"together-sales-early-15","level":"early","profession":"sales","title":"The negotiation email under real constraints","scenario":"A prospect wants a discount, a faster timeline, and an extra feature. You can give on one, must hold two. The email needs to concede gracefully, hold firm clearly, and keep the deal moving — all without sounding rigid.","task":"Write the full email: what you'll give, what you can't, and the path to yes.","tips":["Lead with the yes you can give.","Hold the two firm lines with brief, honest reasons.","End with a concrete next step so momentum survives."],"focus":["impact","clarity"]},
    {"id":"together-sales-early-16","level":"early","profession":"sales","title":"The lost-deal debrief that teaches","scenario":"You lost a deal and your manager wants a debrief. It should state the loss plainly, give precise causes, separate fact from your inference, and land one lesson — useful to the team, not just a postmortem.","task":"Write the full debrief: outcome, causes (fact vs. inference), one actionable lesson.","tips":["State the loss and the stated reason first.","Separate what they told you from what you suspect.","End with one thing the team should do differently."],"focus":["precision","structure"],"placeholder":"Lost Hartwell to CompetitorX. Their stated reason: price, 30% under us (fact). My read: our slow post-demo follow-up cooled them (inference). The lesson —"},
    {"id":"together-sales-early-17","level":"early","profession":"sales","title":"The re-engagement email to a cold prospect","scenario":"A promising prospect went dark two months ago. Your re-engagement email must earn the reopen with a new reason, stay short, respect her silence, and offer a low-friction next step — no guilt, no 'just circling back.'","task":"Write the full email under 70 words with a genuine new reason to reply.","tips":["Lead with something new and relevant, not 'following up.'","Keep it short and pressure-free.","One easy next step, easy to say yes to."],"focus":["concision","audience"]},
    {"id":"together-sales-early-18","level":"early","profession":"sales","title":"The whole discovery call, planned","scenario":"You're preparing to run a discovery call. You need an opening that signposts, three question themes tied to what you sell, and a close that sets a concrete next step — a plan that keeps you in control without a script.","task":"Write the call plan: a 2-sentence opener, three question themes, a 2-sentence close.","tips":["Open by framing the call's purpose and time.","Group your questions into three themes, not a scattershot list.","Close by proposing the specific next step and date."],"focus":["structure","audience"]},
    {"id":"together-sales-early-19","level":"early","profession":"sales","title":"The exec-intro email that lands","scenario":"Your manager will forward your email to a prospect's VP to open a door. It must be short enough for a VP, lead with peer-level relevance, state the ask plainly, and read like it came from your manager's altitude.","task":"Write the forwardable email under 80 words at VP-to-VP register.","tips":["Peer-level relevance, not a pitch.","One clear ask: a short conversation.","Written so your manager can send it unedited."],"focus":["audience","concision"]},
    {"id":"together-sales-early-20","level":"early","profession":"sales","title":"The tough customer QBR opener","scenario":"You're opening a check-in with a customer whose usage has dropped. The opener must acknowledge the real problem without spin, own a plan, and set a collaborative tone — clear, confident, and honest.","task":"Write the 3-4 sentence opener: the honest fact, your read, and the plan for the meeting.","tips":["State the real usage number, no spin.","Own a plan rather than assigning blame.","Set the meeting up as solving it together."],"focus":["impact","precision"],"placeholder":"Let's be straight about the numbers before anything else: your team's usage dropped 20% last quarter. Here's my read on why, and what I'd like to fix together today."},
    {"id":"together-sales-early-21","level":"early","profession":"sales","title":"The multi-thread reply, all together","scenario":"A prospect's email raises pricing, a security question, and demo scheduling. Your reply must be structured into clear blocks, precise on each answer, put the action item first, and stay scannable.","task":"Write the full reply: one-line summary, three labeled blocks, action item first.","tips":["Open by naming the three items so she can navigate.","One clean block per thread, labeled.","Lead with the block that needs her action."],"focus":["structure","concision"],"placeholder":"Three things: the demo time to confirm (needs you), the security answer, and revised pricing — in that order below."},
    {"id":"together-sales-early-22","level":"early","profession":"sales","title":"The 'why us' answer, fully built","scenario":"A prospect asks 'why should we pick you?' on a call. Your spoken answer needs PREP structure, one real differentiator, a concrete customer example, and confident ownership — no rambling into features.","task":"Write the full PREP answer in 4-5 sentences: point, reason, example, point.","tips":["Point first: the one difference that matters to her.","One reason, one concrete customer example.","Land back on the point — don't trail into a feature list."],"focus":["structure","impact"]},
    {"id":"together-sales-early-23","level":"early","profession":"sales","title":"The internal ask for a bigger role","scenario":"In your review you're making the case for a promotion or bigger territory. The message needs a clear ask up front, precise evidence of your results, a forward-looking narrative, and confident ownership.","task":"Write the full 4-5 sentence case: the ask, the evidence, what it unlocks.","tips":["State the ask plainly in sentence one.","Back it with specific numbers, not adjectives.","End with what you'd do with it — the forward story."],"focus":["impact","precision"],"placeholder":"I'd like to move up to the enterprise segment next quarter. I've hit 115% two quarters running on mid-market —"},
    {"id":"together-sales-early-24","level":"early","profession":"sales","title":"The apology-and-recover message","scenario":"You missed a customer commitment and need one message that owns the lapse cleanly, gives a reliable new plan, rebuilds confidence, and stays concise — clear, kind, and no groveling.","task":"Write the full message: ownership, the fix with a firm date, one confidence-rebuilding step.","tips":["Own it in the first sentence, no excuse cushion.","Give a firm, reliable new date.","Add one proactive step that rebuilds trust."],"focus":["clarity","impact"]},
    {"id":"together-sales-early-25","level":"early","profession":"sales","title":"The end-to-end deal summary for handover","scenario":"You're going on leave and handing three active deals to a teammate. For the top one, write a summary that structures the state, is precise on numbers and next steps, flags the risk, and gives your honest read — everything a stranger needs to run it.","task":"Write the full summary for one deal: status, key facts, next step with date, risk, your read.","tips":["Lead with the deal's status in one line.","Facts and commitments in a scannable block, with dates and owners.","End with the one risk and your honest read on the odds."],"focus":["structure","precision"],"placeholder":"Northgate: contract stage, $24K, verbal yes, targeting the 28th. Key facts, next steps, and the one risk below —"}
  ],
};
